const C = { navy:"#0A1E5E", accent:"#2E6BFF", bg:"#F4F6FB", card:"#FFFFFF", ink:"#0F172A", muted:"#64748B", border:"#E2E8F0" };
const RAG = { Green:"#16A34A", Amber:"#F59E0B", Red:"#DC2626" };
const ROLE = { "Maintain":"#64748B", "Double Down":"#2E6BFF", "Rationalize":"#F59E0B", "Venture":"#8B5CF6", "New product":"#DB2777", "Unmapped":"#CBD5E1" };
const GNBC = { "GNB":"#2E6BFF","Retention":"#0EA5E9","Both":"#8B5CF6","Not applicable":"#94A3B8","N/A":"#94A3B8" };
const PROG = { "Released":1,"Done":1,"Release sign off":0.92,"In UAT Review":0.75,"Ready for UAT":0.7,"QA / Testing":0.6,"Ready for QA":0.55,"Code review":0.5,"In progress":0.4,"Blocked":0.3,"Ready for work":0.15,"To Do":0.05,"On hold":0.05,"Cancelled":0 };
const DONE = ["Done","Released","Release sign off"];
const parse = (s)=> s ? new Date(s+"T00:00:00") : null;
const fmt = (s)=> s ? new Date(s+"T00:00:00").toLocaleDateString("en-GB",{day:"2-digit",month:"short",year:"numeric"}) : "—";

const issuesByKey = Object.fromEntries(DATA.issues.map(i=>[i.key,i]));

// Map every product sub-group to its portfolio role from the product tree.
const SUBROLE = {};
const SUBMETA = {}; // sub -> {family, group, role}
Object.entries(DATA.productTree).forEach(([fam,groups])=>Object.entries(groups).forEach(([grp,subs])=>subs.forEach(s=>{ SUBROLE[s.sub]=s.role; SUBMETA[s.sub]={family:fam,group:grp,role:s.role}; })));
// Distribution of portfolio roles across an item's product sub-groups, as % of sub-groups in each role.
function roleDistFromSubs(item){
  if(!item.subgroups || item.subgroups.length===0) return [];
  const counts={};
  item.subgroups.forEach(sg=>{ const r=SUBROLE[sg]; if(r) counts[r]=(counts[r]||0)+1; });
  const total=Object.values(counts).reduce((a,b)=>a+b,0);
  if(!total) return [];
  return Object.entries(counts).map(([role,count])=>({role,count,pct:Math.round(count/total*100)})).sort((a,b)=>b.count-a.count);
}

function ragOf(it){
  const done = DONE.includes(it.status), today=parse(DATA.snapshot);
  const start=parse(it.start), due=parse(it.due);
  const overdue = due && !done && due<today;
  const m = DATA.moves[it.key]||0;
  let depRed=false, depAmber=false;
  DATA.deps.filter(d=>d.src===it.key).forEach(d=>{
    const t=issuesByKey[d.tgt]; const tdue=t&&parse(t.due); const tdone=t&&DONE.includes(t.status);
    const trouble = t && (t.status==="Blocked" || (tdue && !tdone && tdue<today));
    if(d.critical && trouble) depRed=true; else if(d.critical||trouble||d.crossBU) depAmber=true;
  });
  let lag=false;
  if(start&&due&&!done){ const el=(today-start)/(due-start), pr=PROG[it.status]??0; if(el>0 && el-pr>0.25) lag=true; }
  const reasons=[];
  if(done) return {rag:"Green",reasons:["Delivered / released"]};
  if(it.status==="Blocked") reasons.push("Currently blocked");
  if(overdue) reasons.push("Past due date, not complete");
  if(m>=3) reasons.push("Due date moved "+m+"x");
  if(depRed) reasons.push("Critical dependency blocked / overdue");
  if(it.status==="Blocked"||overdue||m>=3||depRed) return {rag:"Red",reasons};
  if(m>=1) reasons.push("Due date moved "+m+"x");
  if(lag) reasons.push("Behind schedule vs elapsed time");
  if(depAmber) reasons.push("Exposed to cross-boundary / critical dependency");
  if(m>=1||lag||depAmber) return {rag:"Amber",reasons};
  return {rag:"Green",reasons:["On track"]};
}
const ragMap = Object.fromEntries(DATA.issues.map(i=>[i.key, ragOf(i)]));

// Normalise each dependency to provider (must finish first) -> dependent (needs it / receives output).
function depEnds(d){
  if(d.type==="Blocks") return {provider:d.src, providerBU:d.srcBU, dependent:d.tgt, dependentBU:d.tgtBU};
  return {provider:d.tgt, providerBU:d.tgtBU, dependent:d.src, dependentBU:d.srcBU}; // depends on / critically depends on / is blocked by / relates to
}
// Delivering BU = who builds an item (item.bu). Receiving BUs = BUs whose work consumes its output (stored on the item, derived from the dependency graph at build time).
const receivingBUs=(item)=> item.recvBUs||[];
// Ancestry chain [theme, initiative, epic] for any item key.
function pathOf(key){ const out=[]; let cur=issuesByKey[key], guard=0; while(cur&&guard++<6){ out.unshift(cur); cur=cur.parent?issuesByKey[cur.parent]:null; } return out; }
// All descendant keys (inclusive) — so themes/initiatives can roll up their epics' dependencies.
function descKeys(key){ const out=[key],stack=[key]; while(stack.length){ const k=stack.pop(); DATA.issues.forEach(i=>{ if(i.parent===k){ out.push(i.key); stack.push(i.key);} }); } return out; }
const outDepsOf=(key)=>{ const ks=new Set(descKeys(key)); return DATA.deps.filter(d=>ks.has(d.src)&&(d.crossBU||d.crossTheme)); };
const inDepsOf =(key)=>{ const ks=new Set(descKeys(key)); return DATA.deps.filter(d=>ks.has(d.tgt)); };
// Health of a single dependency, from the provider side and date alignment.
function depStatus(d){
  const {provider,dependent}=depEnds(d);
  const p=issuesByKey[provider], dep=issuesByKey[dependent], today=parse(DATA.snapshot);
  if(!p||!dep) return {rag:"Amber",label:"Unknown",aligned:null,note:"Linked item not in snapshot"};
  if(d.type==="Relates to") return {rag:"Green",label:"Informational",aligned:null,note:"Related, no blocking order"};
  const pDone=DONE.includes(p.status), pDue=parse(p.due), depDue=parse(dep.due);
  const pBlocked=p.status==="Blocked", pOverdue=pDue&&!pDone&&pDue<today;
  const misaligned = pDue&&depDue&&pDue>depDue; // provider lands after the dependent needs it
  let rag,label,note;
  if(pDone){rag="Green";label="Cleared";note="Dependency already delivered";}
  else if(pBlocked||pOverdue||(d.critical&&misaligned)){rag="Red";label="At risk";note=pBlocked?"Provider is blocked":pOverdue?"Provider past due":"Critical + dates don't align";}
  else if(misaligned){rag="Amber";label="Watch";note="Provider due after it's needed";}
  else if(d.critical){rag="Amber";label="Watch";note="Critical link, provider progressing";}
  else {rag="Green";label="On track";note="Provider on track, dates align";}
  return {rag,label,aligned: (pDue&&depDue)? !misaligned : null, note};
}

const Chip = ({label,color,solid,onClick,title})=> (
  <span onClick={onClick} title={title} style={{ background: solid?color:(color?color+"1A":"#EEF2F9"), color: solid?"#fff":(color||C.muted),
    borderRadius:5, padding:"1px 7px", fontSize:11, fontWeight:600, whiteSpace:"nowrap", cursor:onClick?"pointer":"default" }}>{label}</span>
);
const BarChip = ({label,color,onClick,title})=> (
  <span onClick={onClick} title={title} style={{ background:"rgba(255,255,255,0.94)", color:color||C.ink, border:"1px solid "+((color||"#94A3B8")+"AA"),
    borderRadius:4, padding:"0 5px", fontSize:10, fontWeight:700, whiteSpace:"nowrap", cursor:onClick?"pointer":"default", lineHeight:"15px" }}>{label}</span>
);
const RagDot = ({rag,size=10})=> <span style={{display:"inline-block",width:size,height:size,borderRadius:999,background:RAG[rag]||C.muted}} />;
const TYPESHORT={"Major Theme":"Theme","Initiative":"Initiative","Epic":"Epic"};
const PathLabel = ({k})=>{
  const p=pathOf(k); if(!p.length) return <span style={{fontSize:12}}>{k}</span>;
  const leaf=p[p.length-1], anc=p.slice(0,-1);
  return (<div style={{minWidth:175,maxWidth:250}}>
    <div style={{fontWeight:700,fontSize:12.5,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}><span style={{fontSize:9,fontWeight:700,color:C.muted,border:"1px solid "+C.border,borderRadius:3,padding:"0 4px",marginRight:5}}>{TYPESHORT[leaf.type]||leaf.type}</span>{leaf.summary}</div>
    {anc.length>0 && <div style={{fontSize:10.5,color:C.muted,marginTop:2}}>{anc.map(a=>a.summary).join("  ▸  ")}</div>}
    <div style={{fontSize:10,color:"#94A3B8",marginTop:1}}>{leaf.key} · {leaf.status}</div>
  </div>);
};
const TrendIcon = ({t})=> {
  const map={Improving:["RAG trend: improving vs last period",<TrendingUp size={14} color={RAG.Green}/>],
    Deteriorating:["RAG trend: deteriorating vs last period",<TrendingDown size={14} color={RAG.Red}/>],
    Stable:["RAG trend: stable vs last period",<Minus size={14} color={C.muted}/>]};
  const [title,icon]=map[t]||map.Stable;
  return <span title={title} style={{display:"inline-flex",cursor:"help"}}>{icon}</span>;
};

function useDomain(issues){
  return useMemo(()=>{
    let lo=Infinity,hi=-Infinity;
    issues.forEach(i=>{const s=parse(i.start),d=parse(i.due); if(s)lo=Math.min(lo,s); if(d)hi=Math.max(hi,d);});
    const start=new Date(lo); start.setMonth(Math.floor(start.getMonth()/3)*3,1);
    const end=new Date(hi); end.setMonth(Math.floor(end.getMonth()/3)*3+3,1);
    const quarters=[]; const cur=new Date(start);
    while(cur<end){quarters.push(new Date(cur)); cur.setMonth(cur.getMonth()+3);}
    return {start,end,quarters};
  },[issues]);
}
const pct = (date,dom)=> date?Math.max(0,Math.min(100,((date-dom.start)/(dom.end-dom.start))*100)):0;

export default function ExecDashboard(){
  const [tab,setTab]=useState("roadmap");
  const [showAll,setShowAll]=useState(false);
  const [unplanned,setUnplanned]=useState(true);
  const [expanded,setExpanded]=useState(()=>new Set());
  const [buF,setBuF]=useState(new Set());
  const [buMode,setBuMode]=useState("delivering"); // delivering | receiving | both
  const [roleF,setRoleF]=useState(new Set());
  const [pgaF,setPgaF]=useState(new Set());
  const [focusF,setFocusF]=useState(new Set());
  const [detail,setDetail]=useState(null);
  const [pop,setPop]=useState(null); // {kind, item, x, y}
  const [qShow,setQShow]=useState("all");
  const [depView,setDepView]=useState("overview"); // overview | viz
  const [kpi,setKpi]=useState(null); // KPI drilldown key
  const [okrTip,setOkrTip]=useState(null); // {x,y,pga,chain,focus}
  const [depScope,setDepScope]=useState("all"); // all | critical
  const [depSrcBU,setDepSrcBU]=useState(new Set());
  const [depTgtBU,setDepTgtBU]=useState(new Set());

  const issues=DATA.issues;
  const themes=issues.filter(i=>i.type==="Major Theme");
  const standalone=issues.filter(i=>i.type==="Initiative"&&!i.parent&&!i.unplanned);
  const childrenOf=(k)=>issues.filter(i=>i.parent===k);
  const critByKey=Object.fromEntries(DATA.crit.map(c=>[c.key,c]));
  const full=useDomain(issues);
  const dom=useMemo(()=>{ if(qShow==="all")return full; const start=new Date(full.start); const end=new Date(full.start); end.setMonth(end.getMonth()+3*qShow,1); const quarters=[]; const cur=new Date(start); while(cur<end){quarters.push(new Date(cur)); cur.setMonth(cur.getMonth()+3);} return {start,end,quarters}; },[full,qShow]);
  const today=parse(DATA.snapshot);

  const allBUs=[...new Set(issues.map(i=>i.bu))].sort();
  const allRoles=["Maintain","Double Down","Rationalize","Venture"];
  const allPGA=[...new Set(issues.map(i=>i.pga).filter(x=>x&&x!=="N/A"))];
  const allFocus=[...new Set(issues.map(i=>i.focus).filter(x=>x&&x!=="N/A"))].sort();
  const toggle=(set,setter,v)=>{const n=new Set(set); n.has(v)?n.delete(v):n.add(v); setter(n);};

  const crossDeps=DATA.deps.filter(d=>d.crossBU);
  const depAllSrcBU=[...new Set(crossDeps.map(d=>d.srcBU))].sort();
  const depAllTgtBU=[...new Set(crossDeps.map(d=>d.tgtBU))].sort();
  const depRows=crossDeps
    .filter(d=> depScope==="all"||d.critical)
    .filter(d=> depSrcBU.size===0||depSrcBU.has(d.srcBU))
    .filter(d=> depTgtBU.size===0||depTgtBU.has(d.tgtBU))
    .sort((a,b)=> a.srcBU.localeCompare(b.srcBU) || String(a.srcSum).localeCompare(String(b.srcSum)));

  const buMatch=(i)=>{
    if(buF.size===0) return true;
    const del=buF.has(i.bu);
    const rec=receivingBUs(i).some(b=>buF.has(b));
    return buMode==="delivering"?del : buMode==="receiving"?rec : (del||rec);
  };
  const matches=(i)=> buMatch(i) && (roleF.size===0||i.roles.some(r=>roleF.has(r)))
    && (pgaF.size===0||pgaF.has(i.pga)) && (focusF.size===0||focusF.has(i.focus)) && (unplanned||!i.unplanned);
  const passKids=(i)=> matches(i) || childrenOf(i.key).some(c=>matches(c)||childrenOf(c.key).some(matches));
  const anyFilter = buF.size>0||roleF.size>0||pgaF.size>0||focusF.size>0;
  // When a filter is applied, open the branches that contain matches (so they reveal) — but keep them collapsible.
  useEffect(()=>{
    if(!anyFilter){ setExpanded(new Set()); return; }
    const open=new Set();
    themes.forEach(t=>{
      const kids=childrenOf(t.key);
      if(kids.some(c=>matches(c)||childrenOf(c.key).some(matches))) open.add(t.key);
      kids.forEach(ini=>{ if(childrenOf(ini.key).some(matches)) open.add(ini.key); });
    });
    setExpanded(open);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[buF,roleF,pgaF,focusF,buMode,showAll,unplanned]);

  const bottlenecks=useMemo(()=>{
    const m={};
    DATA.deps.forEach(d=>{ if(!m[d.tgt]) m[d.tgt]={key:d.tgt,summary:d.tgtSum,bu:d.tgtBU,themes:new Set(),bus:new Set(),feedsExec:false,count:0};
      const x=m[d.tgt]; x.count++; if(d.srcTheme)x.themes.add(d.srcTheme); x.bus.add(d.srcBU);
      const st=themes.find(t=>t.key===d.srcTheme); if(st&&st.execTop)x.feedsExec=true; });
    return Object.values(m).map(x=>({...x,themes:x.themes.size,bus:x.bus.size})).sort((a,b)=>b.themes-a.themes);
  },[]);
  const hubCount=bottlenecks.filter(b=>b.themes>=3).length;
  const outDeps=outDepsOf;
  const inDeps=inDepsOf;

  const rows=[];
  const top=[...(showAll?themes:themes.filter(t=>t.execTop)), ...(showAll?standalone:[])];
  top.forEach(t=>{ if(!passKids(t))return;
    const show=(k)=>expanded.has(k);
    rows.push({item:t,level:0,context:anyFilter&&!matches(t)});
    if(show(t.key)) childrenOf(t.key).filter(i=>matches(i)||childrenOf(i.key).some(matches)).forEach(ini=>{
      rows.push({item:ini,level:1,context:anyFilter&&!matches(ini)});
      if(show(ini.key)) childrenOf(ini.key).filter(matches).forEach(ep=>rows.push({item:ep,level:2,context:false}));
    });
  });

  const execList=themes.filter(t=>t.execTop);
  const ragMix={Green:0,Amber:0,Red:0}; execList.forEach(t=>ragMix[ragMap[t.key].rag]++);
  const escalated=DATA.blockers.filter(b=>b.status!=="Resolving").length;
  const totalMoves=Object.values(DATA.moves).reduce((a,b)=>a+b,0);

  const openPop=(e,kind,item)=>{e.stopPropagation(); const r=e.currentTarget.getBoundingClientRect(); setPop({kind,item,x:Math.min(r.left,window.innerWidth-330),y:r.bottom+4});};

  return (
    <div style={{background:C.bg,minHeight:"100vh",color:C.ink,fontFamily:"ui-sans-serif, system-ui, Arial"}}>
      <div style={{background:C.navy,color:"#fff",padding:"16px 24px"}}>
        <div className="flex items-center justify-between flex-wrap gap-2">
          <div><div style={{fontSize:20,fontWeight:800,letterSpacing:-0.3}}>MA PDLC — Executive Dashboard</div>
            <div style={{fontSize:12.5,opacity:0.7}}>Are we delivering the right things? · Are we on track? · What do we act on?</div></div>
          <div style={{fontSize:12,opacity:0.8,textAlign:"right"}}>Snapshot · {fmt(DATA.snapshot)}<br/><span style={{opacity:0.6}}>illustrative data</span></div>
        </div>
      </div>

      <div className="flex flex-wrap gap-3" style={{padding:"14px 24px 0"}}>
        <Tile label="Exec deliverables" value={execList.length} sub="critical themes tracked · click to explore" onClick={()=>setKpi("exec")}/>
        <Tile label="RAG (computed)" value={<span className="flex items-center gap-3" style={{fontSize:18}}>
          <span className="flex items-center gap-1"><RagDot rag="Green"/>{ragMix.Green}</span>
          <span className="flex items-center gap-1"><RagDot rag="Amber"/>{ragMix.Amber}</span>
          <span className="flex items-center gap-1"><RagDot rag="Red"/>{ragMix.Red}</span></span>} sub="from delivery signals · click to explore" onClick={()=>setKpi("rag")}/>
        <Tile label="Blocked" value={DATA.blockers.length} sub={escalated+" escalated · click to explore"} accent={DATA.blockers.length?RAG.Red:undefined} onClick={()=>setKpi("blocked")}/>
        <Tile label="Key bottlenecks" value={hubCount} sub="≥3 themes on one item · click to explore" accent={hubCount?RAG.Amber:undefined} onClick={()=>setKpi("bottlenecks")}/>
        <Tile label="Date slippage" value={totalMoves} sub="due-date moves logged · click to explore" accent={totalMoves?RAG.Amber:undefined} onClick={()=>setKpi("slippage")}/>
        <Tile label="Unplanned load" value={DATA.unplanned.total} sub={(DATA.unplanned.byBU.length)+" BUs · click to explore"} accent={RAG.Amber} onClick={()=>setKpi("unplanned")}/>
      </div>

      <div className="flex gap-1 items-center flex-wrap" style={{padding:"14px 24px 0"}}>
        {[["roadmap","Roadmap"],["deps","Dependencies"],["invest","Investment"],["strategy","Strategy"],["actions","Actions"]].map(([k,l])=>(
          <button key={k} onClick={()=>setTab(k)} style={{border:"none",cursor:"pointer",padding:"8px 16px",fontSize:13.5,fontWeight:600,
            borderRadius:"8px 8px 0 0",background:tab===k?C.card:"transparent",color:tab===k?C.navy:C.muted,
            boxShadow:tab===k?"0 -1px 0 "+C.accent+" inset":"none"}}>{l}</button>))}
        <div style={{flex:1}}/>
        <Toggle on={unplanned} set={()=>setUnplanned(!unplanned)} label={unplanned?"Unplanned work: included":"Unplanned work: excluded"}/>
      </div>

      <div style={{padding:"0 24px 32px"}}>
        {tab==="roadmap" && (
          <div style={{background:C.card,borderRadius:"0 8px 8px 8px",border:"1px solid "+C.border,padding:16}}>
            <div className="flex flex-wrap items-center gap-3" style={{marginBottom:10}}>
              <Toggle on={showAll} set={()=>setShowAll(!showAll)} label={showAll?"All themes":"Exec priorities only"}/>
              <div className="flex items-center gap-1.5 flex-wrap">
                <span style={{fontSize:11.5,color:C.muted,fontWeight:600}}>BU:</span>
                <div className="flex" style={{border:"1px solid "+C.border,borderRadius:7,overflow:"hidden"}}>
                  {[["delivering","Delivering"],["receiving","Receiving"],["both","Both"]].map(([k,l])=>(
                    <button key={k} title={k==="delivering"?"BU that builds the item":k==="receiving"?"BU whose work depends on the item":"Either delivering or receiving"} onClick={()=>setBuMode(k)} style={{border:"none",cursor:"pointer",padding:"4px 9px",fontSize:11,fontWeight:700,background:buMode===k?C.navy:"#fff",color:buMode===k?"#fff":C.muted}}>{l}</button>))}
                </div>
                {allBUs.map(o=>{const active=buF.has(o); return <button key={o} onClick={()=>toggle(buF,setBuF,o)} style={{border:"1px solid "+(active?C.accent:C.border),background:active?C.accent+"1A":"#fff",color:active?C.accent:C.muted,borderRadius:14,padding:"3px 10px",fontSize:11.5,cursor:"pointer",fontWeight:600}}>{o}</button>;})}
              </div>
              <FilterGroup label="Role" opts={allRoles} sel={roleF} onToggle={v=>toggle(roleF,setRoleF,v)} colorMap={ROLE}/>
              <FilterGroup label="PGA" opts={allPGA} sel={pgaF} onToggle={v=>toggle(pgaF,setPgaF,v)}/>
              <FilterGroup label="OKR focus" opts={allFocus} sel={focusF} onToggle={v=>toggle(focusF,setFocusF,v)} shorten/>
              {(buF.size||roleF.size||pgaF.size||focusF.size)>0 && <button onClick={()=>{setBuF(new Set());setRoleF(new Set());setPgaF(new Set());setFocusF(new Set());}} style={{fontSize:12,color:C.accent,background:"none",border:"none",cursor:"pointer"}}>clear</button>}
              <div style={{flex:1}}/>
              <div className="flex items-center gap-1"><span style={{fontSize:11.5,color:C.muted,fontWeight:600}}>Quarters:</span>{[4,6,8,"all"].map(n=>(<button key={n} onClick={()=>setQShow(n)} style={{border:"1px solid "+(qShow===n?C.accent:C.border),color:qShow===n?C.accent:C.muted,background:"#fff",borderRadius:6,padding:"3px 9px",fontSize:11.5,cursor:"pointer",fontWeight:600}}>{n==="all"?"All":n}</button>))}</div>
            </div>
            <div className="flex" style={{borderBottom:"1px solid "+C.border,paddingBottom:6,fontSize:10,color:C.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.4}}>
              <div style={{width:286,flexShrink:0}}>Deliverable · PGA / OKR</div>
              <div style={{width:56,flexShrink:0,textAlign:"center"}}>GNB</div>
              <div style={{flex:1,position:"relative",height:16}}>
                {dom.quarters.map((q,i)=><div key={i} style={{position:"absolute",left:pct(q,dom)+"%",fontSize:11,color:C.muted,fontWeight:600,transform:"translateX(2px)"}}>Q{Math.floor(q.getMonth()/3)+1} '{String(q.getFullYear()).slice(2)}</div>)}
              </div>
            </div>
            <div style={{overflowX:"hidden"}}>
            {rows.map(({item,level,context})=>{
              const rg=ragMap[item.key]; const cr=critByKey[item.key];
              const left=pct(parse(item.start),dom), right=pct(parse(item.due),dom), width=Math.max(1.5,right-left);
              const prog=PROG[item.status]??0; const hasKids=childrenOf(item.key).length>0&&level<2; const ed=outDeps(item.key).length;
              const okr=item.focus&&item.focus!=="N/A"?(item.focus.split(": ").slice(1).join(": ")||item.focus):null;
              const gnbShort={"GNB":"GNB","Retention":"Ret","Both":"Both","Not applicable":"—","N/A":"—"}[item.gnb]||item.gnb;
              const rdist=roleDistFromSubs(item);
              const recv=receivingBUs(item);
              return (
                <div key={item.key} className="flex items-center" title={context?"Shown for context — doesn't match the current BU filter, but contains items that do":undefined} style={{height:62,borderBottom:"1px solid #F1F5F9",opacity:context?0.5:1}}>
                  <div style={{width:286,flexShrink:0,paddingRight:8,paddingLeft:level*16,overflow:"hidden"}}>
                    <div className="flex items-center gap-1.5">
                      {hasKids?<button onClick={()=>toggle(expanded,setExpanded,item.key)} style={{background:"none",border:"none",cursor:"pointer",padding:0,color:C.muted}}>{expanded.has(item.key)?<ChevronDown size={15}/>:<ChevronRight size={15}/>}</button>:<span style={{width:15,display:"inline-block"}}/>}
                      <RagDot rag={rg.rag} size={9}/>
                      {item.execTop&&<Star size={13} color={C.accent} fill={C.accent}/>}
                      <button onClick={()=>setDetail(item)} title={item.summary} style={{background:"none",border:"none",cursor:"pointer",padding:0,textAlign:"left",fontWeight:level===0?700:600,fontSize:level===0?14:12.5,color:C.ink,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth:220}}>{item.summary}</button>
                    </div>
                    <div onMouseEnter={(e)=>{const r=e.currentTarget.getBoundingClientRect(); setOkrTip({x:Math.min(r.left,window.innerWidth-360),y:r.bottom+4,pga:item.pga,chain:item.okrChain,focus:item.focus,okr:item.okr});}} onMouseLeave={()=>setOkrTip(null)} style={{marginLeft:21,marginTop:4,fontSize:11,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",maxWidth:256,cursor:"help"}}>
                      {item.pga&&item.pga!=="N/A"&&<span style={{color:C.accent,fontWeight:700}}>{item.pga}</span>}
                      {okr&&<span style={{color:C.muted}}>{item.pga&&item.pga!=="N/A"?" · ":""}{okr}</span>}
                      {(!item.pga||item.pga==="N/A")&&!okr&&<span style={{color:"#CBD5E1"}}>—</span>}
                    </div>
                  </div>
                  <div style={{width:56,flexShrink:0,display:"flex",justifyContent:"center"}}>
                    <span title={item.gnb} style={{background:GNBC[item.gnb]+"1A",color:GNBC[item.gnb],border:"1px solid "+GNBC[item.gnb],borderRadius:5,padding:"2px 6px",fontSize:10,fontWeight:700}}>{gnbShort}</span>
                  </div>
                  <div style={{flex:1,position:"relative",height:"100%"}}>
                    {dom.quarters.map((q,i)=><div key={i} style={{position:"absolute",left:pct(q,dom)+"%",top:0,bottom:0,width:1,background:"#EEF2F9"}}/>)}
                    {today&&<div style={{position:"absolute",left:pct(today,dom)+"%",top:0,bottom:0,width:2,background:"#FCA5A5",zIndex:1}}/>}
                    <div onClick={()=>setDetail(item)} title={item.status+" · due "+fmt(item.due)} style={{position:"absolute",left:left+"%",width:width+"%",top:2,height:58,cursor:"pointer",zIndex:2}}>
                      <div style={{position:"absolute",inset:0,borderRadius:6,background:RAG[rg.rag]+"2E",border:"1px solid "+RAG[rg.rag],overflow:"hidden"}}>
                        <div style={{position:"absolute",left:0,top:0,bottom:0,width:(prog*100)+"%",background:RAG[rg.rag]+"3D"}}/>
                      </div>
                      <div style={{position:"absolute",left:6,top:0,bottom:0,display:"flex",flexDirection:"column",justifyContent:"center",gap:2,whiteSpace:"nowrap"}}>
                        <div className="flex items-center gap-1"><BarChip title={"Delivering BU: "+item.bu} label={"Del · "+item.bu} color={C.navy}/>{recv.length>0&&<BarChip title={"Receiving BU(s): "+recv.join(", ")} label={"Rec · "+(recv.length<=2?recv.join(", "):recv[0]+" +"+(recv.length-1))} color={"#0EA5E9"}/>}{(DATA.moves[item.key]||0)>0&&<BarChip label={"moved "+DATA.moves[item.key]+"x"} color="#B45309"/>}{cr&&<TrendIcon t={cr.trend}/>}</div>
                        <div className="flex items-center gap-1">{rdist.length>0?rdist.slice(0,4).map(d=><BarChip key={d.role} title={d.count+" of "+item.subgroups.length+" sub-groups · "+d.role} label={d.role+" "+d.pct+"%"} color={ROLE[d.role]}/>):<BarChip label={item.newprod==="New"?"New product":"no role"} color={item.newprod==="New"?ROLE["New product"]:"#94A3B8"}/>}</div>
                        <div className="flex items-center gap-1">{item.families.length>0?<BarChip color={C.accent} onClick={(e)=>openPop(e,"products",item)} label={<span className="flex items-center" style={{gap:3}}><Boxes size={9}/>{item.families.length===1?item.families[0]:item.families.length+" families"}</span>}/>:<BarChip label="—" color="#94A3B8"/>}{ed>0&&<BarChip color="#B45309" onClick={(e)=>openPop(e,"deps",item)} title="cross-boundary dependencies" label={<span className="flex items-center" style={{gap:2}}><GitBranch size={10}/>{ed}</span>}/>}</div>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
            </div>
            {rows.length===0&&<div style={{padding:30,textAlign:"center",color:C.muted}}>No items match the current filters.</div>}
            <Legend/>
          </div>
        )}

        {tab==="deps" && (
          <div style={{background:C.card,borderRadius:"0 8px 8px 8px",border:"1px solid "+C.border,padding:18}}>
            <div className="flex gap-1" style={{marginBottom:14}}>
              {[["overview","Overview"],["viz","Visualisation"]].map(([k,l])=>(<button key={k} onClick={()=>setDepView(k)} style={{border:"1px solid "+(depView===k?C.accent:C.border),background:depView===k?C.accent+"14":"#fff",color:depView===k?C.accent:C.muted,borderRadius:8,padding:"6px 14px",fontSize:12.5,fontWeight:700,cursor:"pointer"}}>{l}</button>))}
            </div>
            {depView==="overview" && (<>
            <SectionTitle>Key dependencies — bottlenecks by fan-in</SectionTitle>
            <p style={{fontSize:12.5,color:C.muted,margin:"2px 0 14px"}}>Items many deliverables depend on — surfaced even when not exec priority themselves. If one slips it can stall multiple themes. The left border and dot show the item's <b>RAG status</b> (green / amber / red); the <b style={{color:C.navy}}>feeds exec</b> badge marks ones an exec priority depends on. Click a card to open it.</p>
            <div className="flex flex-wrap gap-3">
              {bottlenecks.filter(b=>b.themes>=2).slice(0,8).map(b=>{const brag=ragMap[b.key]?ragMap[b.key].rag:null; return (
                <div key={b.key} onClick={()=>issuesByKey[b.key]&&setDetail(issuesByKey[b.key])} style={{width:290,border:"1px solid "+C.border,borderRadius:8,padding:12,borderLeft:"4px solid "+(brag?RAG[brag]:C.muted),cursor:"pointer"}}>
                  <div className="flex items-center justify-between gap-2"><span className="flex items-center gap-1.5" style={{fontWeight:700,fontSize:13}}>{brag&&<RagDot rag={brag} size={9}/>}{b.summary}</span>{b.feedsExec&&<Chip label="feeds exec" color={C.navy} solid/>}</div>
                  <div style={{fontSize:11.5,color:C.muted,marginTop:2}}>{b.key} · {b.bu}{brag?" · RAG: "+brag:""}</div>
                  <div className="flex items-end justify-between" style={{marginTop:10}}><span className="flex gap-4"><Stat n={b.themes} l="themes"/><Stat n={b.bus} l="BUs"/><Stat n={b.count} l="links"/></span><span style={{fontSize:11,color:C.accent,fontWeight:700}}>Details →</span></div>
                </div>);})}
            </div>
            <SectionTitle style={{marginTop:22}}>Cross-BU dependencies</SectionTitle>
            <p style={{fontSize:12.5,color:C.muted,margin:"2px 0 10px"}}>Each link shows the source and the item it depends on, with full hierarchy (theme → initiative → epic), how the two due dates line up, and whether the dependency is on track. Status looks at the item that must finish first.</p>
            <div className="flex flex-wrap items-center gap-3" style={{marginBottom:10}}>
              <div className="flex" style={{border:"1px solid "+C.border,borderRadius:8,overflow:"hidden"}}>
                {[["all","All"],["critical","Critical only"]].map(([k,l])=>(<button key={k} onClick={()=>setDepScope(k)} style={{border:"none",cursor:"pointer",padding:"6px 14px",fontSize:12.5,fontWeight:700,background:depScope===k?C.navy:"#fff",color:depScope===k?"#fff":C.muted}}>{l}</button>))}
              </div>
              <FilterGroup label="Source BU" opts={depAllSrcBU} sel={depSrcBU} onToggle={v=>toggle(depSrcBU,setDepSrcBU,v)}/>
              <FilterGroup label="Dependent BU" opts={depAllTgtBU} sel={depTgtBU} onToggle={v=>toggle(depTgtBU,setDepTgtBU,v)}/>
              {(depSrcBU.size||depTgtBU.size)>0 && <button onClick={()=>{setDepSrcBU(new Set());setDepTgtBU(new Set());}} style={{fontSize:12,color:C.accent,background:"none",border:"none",cursor:"pointer"}}>clear</button>}
              <div style={{flex:1}}/>
              <span style={{fontSize:11.5,color:C.muted}}>{depRows.length} link{depRows.length===1?"":"s"}</span>
            </div>
            <Table head={["Source BU","Source","Relationship","Dependent BU","Depends on","Due dates","Status"]}
              rows={depRows.map(d=>{
                const s=issuesByKey[d.src], t=issuesByKey[d.tgt]; const st=depStatus(d);
                return [
                  <Chip label={d.srcBU} color={C.navy}/>,
                  <PathLabel k={d.src}/>,
                  <Chip label={d.type} color={d.critical?RAG.Red:C.muted}/>,
                  <Chip label={d.tgtBU} color={"#0EA5E9"}/>,
                  <PathLabel k={d.tgt}/>,
                  <div style={{fontSize:11.5,whiteSpace:"nowrap"}}>
                    <div><span style={{color:C.muted}}>Source: </span>{s?fmt(s.due):"—"}</div>
                    <div><span style={{color:C.muted}}>Depends on: </span>{t?fmt(t.due):"—"}</div>
                    <div style={{marginTop:2,fontWeight:700,color:st.aligned===null?C.muted:st.aligned?RAG.Green:RAG.Red}}>{st.aligned===null?"— no order":st.aligned?"✓ dates align":"✗ misaligned"}</div>
                  </div>,
                  <span className="flex items-center gap-1.5" title={st.note} style={{whiteSpace:"nowrap",cursor:"help"}}><RagDot rag={st.rag} size={9}/><b style={{color:RAG[st.rag]}}>{st.label}</b></span>
                ];
              })}/>
            {depRows.length===0 && <div style={{padding:20,textAlign:"center",color:C.muted}}>No dependencies match the current filters.</div>}
            </>)}
            {depView==="viz" && <DepViz onOpen={setDetail}/>}
          </div>
        )}

        {tab==="invest" && <Investment unplanned={unplanned}/>}

        {tab==="strategy" && <StrategyMap onOpen={setDetail}/>}

        {tab==="actions" && (
          <div style={{background:C.card,borderRadius:"0 8px 8px 8px",border:"1px solid "+C.border,padding:18}}>
            <SectionTitle>Blockers — what needs acting on</SectionTitle>
            <Table head={["Blocked item","Blocked by","Days","Escalated to","Owner","Consequence","Rev at risk","Status"]}
              rows={DATA.blockers.map(b=>[<span><b style={{fontSize:12.5}}>{b.summary}</b><div style={{fontSize:11,color:C.muted}}>{b.item}</div></span>,b.blockedBy,
                <span style={{color:b.days>60?RAG.Red:b.days>30?RAG.Amber:C.ink,fontWeight:600}}>{b.days}</span>,b.escalatedTo,<Chip label={b.owner} color={C.accent}/>,b.consequence,b.revAtRisk,
                <Chip label={b.status} color={b.status==="Open"?RAG.Red:b.status==="Escalated"?RAG.Amber:RAG.Green}/>])}/>
            <SectionTitle style={{marginTop:22}}>Risks &amp; decisions</SectionTitle>
            <Table head={["Ref","Type","Description","Owner","Required action","Due","Status"]} rows={DATA.risks.map(r=>[r.ref,<Chip label={r.type} color={r.type==="Risk"?RAG.Amber:C.accent}/>,r.desc,r.owner,r.action,fmt(r.due),r.status])}/>
            <SectionTitle style={{marginTop:22}}>Capacity signal <span style={{fontSize:11,fontWeight:500,color:C.muted}}>(placeholder)</span></SectionTitle>
            <div className="flex flex-wrap gap-2">
              {DATA.capacity.map(c=>(<div key={c.squad} className="flex items-center gap-2" style={{border:"1px solid "+C.border,borderRadius:6,padding:"6px 10px",fontSize:12}}>
                <span style={{width:9,height:9,borderRadius:999,background:c.signal==="Critical"?RAG.Red:c.signal==="At risk"?RAG.Amber:RAG.Green}}/><b>{c.squad}</b><span style={{color:C.muted}}>{c.note}</span></div>))}
            </div>
          </div>
        )}
      </div>

      {pop && <Popover pop={pop} onClose={()=>setPop(null)} onJump={(it)=>{setPop(null);setDetail(it);}}/>}
      {okrTip && <OkrTip tip={okrTip}/>}
      {kpi && <KpiModal which={kpi} execList={execList} onClose={()=>setKpi(null)} goTab={(t)=>{setKpi(null);setTab(t);}} onOpen={(it)=>{setKpi(null);setDetail(it);}}/>}
      {detail && <Drawer item={detail} rg={ragMap[detail.key]} cr={critByKey[detail.key]} out={outDeps(detail.key)} inc={inDeps(detail.key)} onClose={()=>setDetail(null)} onJump={(it)=>setDetail(it)}/>}
    </div>
  );
}

function Popover({pop,onClose,onJump}){
  const {kind,item,x,y}=pop;
  return (
    <div onClick={onClose} style={{position:"fixed",inset:0,zIndex:60}}>
      <div onClick={e=>e.stopPropagation()} style={{position:"fixed",left:x,top:y,width:320,maxHeight:340,overflowY:"auto",background:"#fff",border:"1px solid "+C.border,borderRadius:10,boxShadow:"0 10px 30px rgba(0,0,0,0.18)",padding:12,fontSize:12.5}}>
        {kind==="products" ? (<>
          <div style={{fontWeight:700,marginBottom:6}} className="flex items-center gap-1.5"><Boxes size={14} color={C.accent}/> Products in scope</div>
          {item.families.map(fam=>(<div key={fam} style={{marginBottom:8}}>
            <div style={{fontWeight:700,fontSize:12,color:C.navy}}>{fam}</div>
            {Object.entries(DATA.productTree[fam]||{}).map(([grp,subs])=>{
              const inScope=subs.filter(s=>item.subgroups.includes(s.sub)); if(inScope.length===0)return null;
              return <div key={grp} style={{marginLeft:8,marginTop:3}}>
                <div style={{fontSize:11,color:C.muted,fontWeight:600}}>{grp}</div>
                <div className="flex flex-wrap gap-1" style={{marginTop:2}}>{inScope.map(s=><span key={s.sub} title={s.role} style={{fontSize:10.5,border:"1px solid "+ROLE[s.role],color:ROLE[s.role],borderRadius:4,padding:"1px 5px"}}>{s.sub}</span>)}</div>
              </div>;
            })}
          </div>))}
          <div style={{fontSize:11,color:C.muted,marginTop:4}}>{item.subgroups.length} sub-groups · roles: {item.roles.join(", ")}</div>
        </>) : (<>
          <div style={{fontWeight:700,marginBottom:6}} className="flex items-center gap-1.5"><GitBranch size={14} color="#B45309"/> Cross-boundary dependencies</div>
          {outDepsOf(item.key).map(d=>(
            <div key={d.id} onClick={()=>issuesByKey[d.tgt]&&onJump(issuesByKey[d.tgt])} style={{padding:"6px 0",borderBottom:"1px solid #F1F5F9",cursor:issuesByKey[d.tgt]?"pointer":"default"}}>
              <div className="flex items-center gap-1.5"><Chip label={d.type} color={d.critical?RAG.Red:C.muted}/>{d.crossBU&&<Chip label="cross-BU"/>}</div>
              {d.src!==item.key&&<div style={{fontSize:10.5,color:"#94A3B8",marginTop:2}}>from {d.srcSum} ({d.srcBU})</div>}
              <div style={{marginTop:3,fontWeight:600}}>depends on {d.tgtSum}</div>
              <div style={{fontSize:11,color:C.muted}}>{d.tgt} · {d.tgtBU}{issuesByKey[d.tgt]?" · click to open":""}</div>
            </div>))}
        </>)}
      </div>
    </div>
  );
}

function Investment({unplanned}){
  const [mode,setMode]=useState("forward"); const [win,setWin]=useState(90); const snap=parse(DATA.snapshot);
  const qStart=(d)=>{const x=new Date(d); x.setMonth(Math.floor(x.getMonth()/3)*3,1); x.setHours(0,0,0,0); return x;};
  const addQ=(d,n)=>{const x=new Date(d); x.setMonth(x.getMonth()+3*n,1); return x;};
  const qEnd=(s)=>{const x=new Date(s); x.setMonth(x.getMonth()+3,0); return x;};
  const cs=qStart(snap);
  const [fwd,setFwd]=useState("current");
  const [cStart,setCStart]=useState(cs.toISOString().slice(0,10));
  const [cEnd,setCEnd]=useState(qEnd(cs).toISOString().slice(0,10));
  const d0=(off)=>{const x=new Date(snap); x.setDate(x.getDate()-off); return x.toISOString().slice(0,10);};
  const [rCustom,setRCustom]=useState(false);
  const [rStart,setRStart]=useState(d0(90));
  const [rEnd,setREnd]=useState(snap.toISOString().slice(0,10));
  const [cmp,setCmp]=useState(false);
  const [cmpDim,setCmpDim]=useState("role");
  const [cmpPeriod,setCmpPeriod]=useState("pq");
  let pStart,pEnd,plabel;
  if(fwd==="current"){pStart=cs;pEnd=qEnd(cs);plabel="current quarter";}
  else if(fwd==="next"){pStart=addQ(cs,1);pEnd=qEnd(addQ(cs,1));plabel="next quarter";}
  else {pStart=parse(cStart);pEnd=parse(cEnd);plabel="selected range";}
  const agg=(items,kf,vf)=>{const m={}; items.forEach(i=>{const k=kf(i); if(!k)return; m[k]=(m[k]||0)+vf(i);}); return Object.entries(m).map(([name,value])=>({name,value:Math.round(value)})).sort((a,b)=>b.value-a.value);};
  let epics=DATA.issues.filter(i=>i.type==="Epic"); if(!unplanned) epics=epics.filter(e=>!e.unplanned);
  const fwdEpics=epics.filter(e=>{const s=parse(e.start),d=parse(e.due); return s&&d&&pStart&&pEnd&&s<=pEnd&&d>=pStart;});
  let logs=DATA.worklogs; if(!unplanned) logs=logs.filter(w=>w.worktype!=="Unplanned Work");
  let winStart,winEnd;
  if(rCustom){ winStart=parse(rStart); winEnd=parse(rEnd); }
  else { winEnd=new Date(snap); winStart=new Date(snap); winStart.setDate(winStart.getDate()-win); }
  const winLen=Math.max(86400000,winEnd-winStart);
  const priorStart=new Date(winStart.getTime()-winLen);
  const inWin=logs.filter(w=>{const d=parse(w.date); return d>=winStart&&d<=winEnd;});
  const inPrior=logs.filter(w=>{const d=parse(w.date); return d>=priorStart&&d<winStart;});
  const winLabel = rCustom?"selected range":({30:"last month",90:"last quarter",365:"last year"}[win]||"window");
  const fwMode=mode==="forward";
  const src=fwMode?fwdEpics:inWin; const vf=fwMode?(i=>i.sp):(i=>i.hours);
  const nb=(it)=> it.newprod==="New" ? "New product" : "Unmapped";
  const byRole = fwMode
    ? (()=>{const m={}; fwdEpics.forEach(e=>{const rs=e.roles&&e.roles.length?e.roles:[nb(e)]; rs.forEach(r=>m[r]=(m[r]||0)+e.sp/rs.length);}); return Object.entries(m).map(([name,value])=>({name,value:Math.round(value)})).sort((a,b)=>b.value-a.value);})()
    : agg(src,i=>i.role||nb(i),vf);
  const byGNB=agg(src,i=>i.gnb,vf), byBU=agg(src,i=>i.bu,vf), byNew=agg(src,i=>i.newprod,vf);
  const unit=fwMode?"story pts":"hours";
  const [pexp,setPexp]=useState(()=>new Set());
  const ptog=(k)=>{const n=new Set(pexp); n.has(k)?n.delete(k):n.add(k); setPexp(n);};
  // Effort by product family -> group -> sub-group
  const ptree=useMemo(()=>{
    const t={}; const add=(fam,grp,sub,v)=>{ if(!v)return; fam=fam||"Unmapped"; grp=grp||"—"; sub=sub||"—";
      t[fam]=t[fam]||{total:0,groups:{}}; t[fam].total+=v;
      const g=t[fam].groups; g[grp]=g[grp]||{total:0,subs:{}}; g[grp].total+=v; g[grp].subs[sub]=(g[grp].subs[sub]||0)+v; };
    if(fwMode){ fwdEpics.forEach(e=>{ const subs=e.subgroups||[]; const v=e.sp||0;
        if(subs.length===0){ add(e.families[0]||"Unmapped","—","—",v); }
        else subs.forEach(s=>{ const m=SUBMETA[s]||{}; add(m.family||e.families[0]||"Unmapped", m.group||"—", s, v/subs.length); }); }); }
    else { inWin.forEach(w=> add(w.family, w.group, w.subgroup, w.hours||0) ); }
    return t;
  },[fwMode,pStart&&pStart.getTime(),pEnd&&pEnd.getTime(),winStart&&winStart.getTime(),winEnd&&winEnd.getTime(),unplanned]);
  const pGrand=Object.values(ptree).reduce((a,f)=>a+f.total,0)||1;
  const fams=Object.entries(ptree).map(([name,v])=>({name,...v})).sort((a,b)=>b.total-a.total);
  const prop=(l)=>{const tot=l.reduce((s,w)=>s+w.hours,0)||1; const m={}; l.forEach(w=>{const k=w.role||nb(w); m[k]=(m[k]||0)+w.hours;}); return Object.fromEntries(Object.entries(m).map(([k,v])=>[k,v/tot]));};
  const pNow=prop(inWin), pPrev=prop(inPrior);
  return (
    <div style={{background:C.card,borderRadius:"0 8px 8px 8px",border:"1px solid "+C.border,padding:18}}>
      <div className="flex flex-wrap items-center gap-3" style={{marginBottom:14}}>
        <div className="flex" style={{border:"1px solid "+C.border,borderRadius:8,overflow:"hidden"}}>
          {[["forward","Forward (story points)"],["retro","Retrospective (time cards)"]].map(([k,l])=>(<button key={k} onClick={()=>setMode(k)} style={{border:"none",cursor:"pointer",padding:"7px 14px",fontSize:12.5,fontWeight:600,background:mode===k?C.navy:"#fff",color:mode===k?"#fff":C.muted}}>{l}</button>))}
        </div>
        {fwMode&&<div className="flex gap-1 items-center">{[["current","Current quarter"],["next","Next quarter"],["custom","Custom range"]].map(([k,l])=>(<button key={k} onClick={()=>setFwd(k)} style={{border:"1px solid "+(fwd===k?C.accent:C.border),color:fwd===k?C.accent:C.muted,background:"#fff",borderRadius:6,padding:"5px 11px",fontSize:12,cursor:"pointer",fontWeight:600}}>{l}</button>))}
          {fwd==="custom"&&<span className="flex items-center gap-1"><input type="date" value={cStart} onChange={e=>setCStart(e.target.value)} style={{border:"1px solid "+C.border,borderRadius:6,padding:"4px 6px",fontSize:12}}/><span style={{color:C.muted}}>→</span><input type="date" value={cEnd} onChange={e=>setCEnd(e.target.value)} style={{border:"1px solid "+C.border,borderRadius:6,padding:"4px 6px",fontSize:12}}/></span>}
        </div>}
        {!fwMode&&<div className="flex gap-1 items-center flex-wrap">{[[30,"Last month"],[90,"Last quarter"],[365,"Last year"]].map(([d,l])=>{const on=!rCustom&&win===d; return <button key={d} onClick={()=>{setRCustom(false);setWin(d);}} style={{border:"1px solid "+(on?C.accent:C.border),color:on?C.accent:C.muted,background:"#fff",borderRadius:6,padding:"5px 11px",fontSize:12,cursor:"pointer",fontWeight:600}}>{l}</button>;})}
          <button onClick={()=>setRCustom(true)} style={{border:"1px solid "+(rCustom?C.accent:C.border),color:rCustom?C.accent:C.muted,background:"#fff",borderRadius:6,padding:"5px 11px",fontSize:12,cursor:"pointer",fontWeight:600}}>Custom range</button>
          {rCustom&&<span className="flex items-center gap-1"><input type="date" value={rStart} onChange={e=>setRStart(e.target.value)} style={{border:"1px solid "+C.border,borderRadius:6,padding:"4px 6px",fontSize:12}}/><span style={{color:C.muted}}>→</span><input type="date" value={rEnd} onChange={e=>setREnd(e.target.value)} style={{border:"1px solid "+C.border,borderRadius:6,padding:"4px 6px",fontSize:12}}/></span>}
        </div>}
        <span style={{fontSize:12,color:C.muted}}>{fwMode?("Planned story points · epics overlapping "+plabel):("Logged hours · "+winLabel)}{unplanned?"":" · unplanned excluded"}.</span>
      </div>
      <div className="flex flex-wrap gap-4">
        <Panel title="By portfolio role"><ResponsiveContainer width="100%" height={210}><PieChart><Pie data={byRole} dataKey="value" nameKey="name" innerRadius={45} outerRadius={80} paddingAngle={2}>{byRole.map((e,i)=><Cell key={i} fill={ROLE[e.name]||"#CBD5E1"}/>)}</Pie><Tooltip/></PieChart></ResponsiveContainer><KeyList data={byRole} colorMap={ROLE}/></Panel>
        <Panel title="GNB vs Retention"><ResponsiveContainer width="100%" height={210}><BarChart data={byGNB} layout="vertical" margin={{left:20}}><XAxis type="number" hide/><YAxis type="category" dataKey="name" width={90} tick={{fontSize:11}}/><Tooltip/><Bar dataKey="value" radius={[0,4,4,0]}>{byGNB.map((e,i)=><Cell key={i} fill={GNBC[e.name]||"#94A3B8"}/>)}</Bar></BarChart></ResponsiveContainer></Panel>
        <Panel title="By business unit"><ResponsiveContainer width="100%" height={210}><BarChart data={byBU} layout="vertical" margin={{left:30}}><XAxis type="number" hide/><YAxis type="category" dataKey="name" width={120} tick={{fontSize:10.5}}/><Tooltip/><Bar dataKey="value" fill={C.accent} radius={[0,4,4,0]}/></BarChart></ResponsiveContainer></Panel>
        <Panel title="New vs existing"><ResponsiveContainer width="100%" height={210}><PieChart><Pie data={byNew} dataKey="value" nameKey="name" outerRadius={80}>{byNew.map((e,i)=><Cell key={i} fill={e.name==="New"?"#8B5CF6":"#94A3B8"}/>)}</Pie><Tooltip/></PieChart></ResponsiveContainer><KeyList data={byNew} colorMap={{New:"#8B5CF6",Existing:"#94A3B8"}}/></Panel>
      </div>
      {!fwMode&&<div style={{marginTop:16}}><SectionTitle>Trend — role mix vs prior period</SectionTitle>
        <div className="flex flex-wrap gap-3" style={{marginTop:6}}>{["Maintain","Double Down","Rationalize","Venture","New product"].map(r=>{const now=(pNow[r]||0)*100,prev=(pPrev[r]||0)*100,delta=now-prev;
          return <div key={r} className="flex items-center gap-2" style={{border:"1px solid "+C.border,borderRadius:6,padding:"6px 10px",fontSize:12}}><span style={{width:9,height:9,borderRadius:999,background:ROLE[r]}}/><b>{r}</b><span style={{color:C.muted}}>{now.toFixed(0)}%</span><span style={{color:delta>1?RAG.Green:delta<-1?RAG.Red:C.muted,fontWeight:600}}>{delta>1?"▲":delta<-1?"▼":"▬"} {Math.abs(delta).toFixed(0)}pt</span></div>;})}</div></div>}
      {fwMode && <div style={{marginTop:16}}>
        <div className="flex items-center gap-3 flex-wrap" style={{marginBottom:4}}><SectionTitle>Plan vs actuals</SectionTitle>
          <Toggle on={cmp} set={()=>setCmp(!cmp)} label={cmp?"comparison on":"compare this plan against past actuals"}/></div>
        {cmp && (()=>{
          let aS,aE,alabel;
          if(cmpPeriod==="pq"){aE=cs; aS=new Date(cs); aS.setMonth(aS.getMonth()-3); alabel="previous quarter";}
          else {const days={m:30,q:90,y:365}[cmpPeriod]; aE=new Date(snap); aS=new Date(snap); aS.setDate(aS.getDate()-days); alabel={m:"last month",q:"last quarter",y:"last year"}[cmpPeriod];}
          const aLogs=logs.filter(w=>{const d=parse(w.date); return d>=aS&&d<=aE;});
          const planE = cmpDim==="role"? byRole : agg(fwdEpics, e=>e[cmpDim]||nb(e), e=>e.sp);
          const actE  = agg(aLogs, w=> cmpDim==="role"?(w.role||nb(w)):(w[cmpDim]||nb(w)), w=>w.hours);
          const pct=(arr)=>{const t=arr.reduce((s,e)=>s+e.value,0)||1; const m={}; arr.forEach(e=>m[e.name]=e.value/t*100); return m;};
          const pp=pct(planE), ap=pct(actE);
          const cats=[...new Set([...Object.keys(pp),...Object.keys(ap)])].sort((a,b)=>((pp[b]||0)+(ap[b]||0))-((pp[a]||0)+(ap[a]||0)));
          const colOf=(c)=> ROLE[c]||GNBC[c]||(c==="New"?"#8B5CF6":c==="Existing"?"#94A3B8":C.accent);
          return <div>
            <div className="flex flex-wrap items-center gap-2" style={{margin:"8px 0"}}>
              <span style={{fontSize:11.5,color:C.muted,fontWeight:600}}>By:</span>
              {[["role","Portfolio role"],["bu","BU"],["gnb","GNB / Retention"],["newprod","New / existing"]].map(([k,l])=>(<button key={k} onClick={()=>setCmpDim(k)} style={{border:"1px solid "+(cmpDim===k?C.accent:C.border),color:cmpDim===k?C.accent:C.muted,background:"#fff",borderRadius:6,padding:"3px 9px",fontSize:11.5,cursor:"pointer",fontWeight:600}}>{l}</button>))}
              <span style={{width:1,height:16,background:C.border,margin:"0 3px"}}/>
              <span style={{fontSize:11.5,color:C.muted,fontWeight:600}}>Actuals:</span>
              {[["m","Last month"],["q","Last quarter"],["pq","Previous quarter"],["y","Last year"]].map(([k,l])=>(<button key={k} onClick={()=>setCmpPeriod(k)} style={{border:"1px solid "+(cmpPeriod===k?C.accent:C.border),color:cmpPeriod===k?C.accent:C.muted,background:"#fff",borderRadius:6,padding:"3px 9px",fontSize:11.5,cursor:"pointer",fontWeight:600}}>{l}</button>))}
            </div>
            <div style={{fontSize:11.5,color:C.muted,marginBottom:8}}>Comparing share of effort (units differ): <b>plan</b> = planned story points for {plabel}; <b>actuals</b> = logged hours for {alabel}.</div>
            <div style={{border:"1px solid "+C.border,borderRadius:8,overflow:"hidden"}}>
              <div className="flex" style={{padding:"6px 10px",background:C.bg,fontSize:10.5,color:C.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.3}}>
                <div style={{flex:1}}></div><div style={{width:150,textAlign:"right"}}>Plan %</div><div style={{width:150,textAlign:"right"}}>Actuals %</div><div style={{width:60,textAlign:"right"}}>Δ</div>
              </div>
              {cats.map(c=>{const p=Math.round(pp[c]||0),a=Math.round(ap[c]||0),dl=p-a; const col=colOf(c); return (
                <div key={c} className="flex items-center" style={{padding:"7px 10px",borderTop:"1px solid #F1F5F9",fontSize:12.5}}>
                  <div style={{flex:1}} className="flex items-center gap-1.5"><span style={{width:9,height:9,borderRadius:2,background:col}}/>{c}</div>
                  <div style={{width:150}} className="flex items-center justify-end gap-2"><span style={{flex:1,height:7,background:"#EEF2F9",borderRadius:3,overflow:"hidden"}}><span style={{display:"block",height:"100%",width:p+"%",background:col}}/></span><b style={{width:30,textAlign:"right"}}>{p}%</b></div>
                  <div style={{width:150}} className="flex items-center justify-end gap-2"><span style={{flex:1,height:7,background:"#EEF2F9",borderRadius:3,overflow:"hidden"}}><span style={{display:"block",height:"100%",width:a+"%",background:col,opacity:0.55}}/></span><b style={{width:30,textAlign:"right"}}>{a}%</b></div>
                  <div style={{width:60,textAlign:"right",fontWeight:700,color:dl>2?RAG.Green:dl<-2?RAG.Red:C.muted}}>{dl>0?"+":""}{dl}</div>
                </div>);})}
              {cats.length===0 && <div style={{padding:16,textAlign:"center",color:C.muted}}>No data for these periods.</div>}
            </div>
          </div>;
        })()}
      </div>}
      <div style={{marginTop:18}}>
        <SectionTitle>Effort by product — family → group → sub-group</SectionTitle>
        <div style={{fontSize:11.5,color:C.muted,margin:"2px 0 8px"}}>{fwMode?"Planned story points":"Logged hours"} attributed down the product hierarchy{fwMode?" (an epic's points split evenly across its sub-groups)":""}. Click a row to drill in.</div>
        <div style={{border:"1px solid "+C.border,borderRadius:8,overflow:"hidden"}}>
          <div className="flex" style={{padding:"6px 10px",background:C.bg,fontSize:10.5,color:C.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.3}}>
            <div style={{flex:1}}>Product</div><div style={{width:90,textAlign:"right"}}>{unit}</div><div style={{width:120,textAlign:"right"}}>share</div>
          </div>
          {fams.map(f=>{const fo=pexp.has("F:"+f.name); const grps=Object.entries(f.groups).map(([name,v])=>({name,...v})).sort((a,b)=>b.total-a.total); return (
            <div key={f.name}>
              <div onClick={()=>ptog("F:"+f.name)} className="flex items-center" style={{padding:"7px 10px",borderTop:"1px solid "+C.border,cursor:"pointer",fontWeight:700,fontSize:13}}>
                <div style={{flex:1}} className="flex items-center gap-1">{fo?<ChevronDown size={14}/>:<ChevronRight size={14}/>}{f.name}</div>
                <div style={{width:90,textAlign:"right"}}>{Math.round(f.total)}</div>
                <div style={{width:120,textAlign:"right"}} className="flex items-center justify-end gap-2"><span style={{flex:1,height:6,background:"#EEF2F9",borderRadius:3,overflow:"hidden"}}><span style={{display:"block",height:"100%",width:(f.total/pGrand*100)+"%",background:C.accent}}/></span>{Math.round(f.total/pGrand*100)}%</div>
              </div>
              {fo && grps.map(g=>{const go=pexp.has("G:"+f.name+"|"+g.name); const subs=Object.entries(g.subs).map(([name,value])=>({name,value})).sort((a,b)=>b.value-a.value); return (
                <div key={g.name}>
                  <div onClick={()=>ptog("G:"+f.name+"|"+g.name)} className="flex items-center" style={{padding:"6px 10px 6px 26px",borderTop:"1px solid #F1F5F9",cursor:"pointer",fontWeight:600,fontSize:12.5,color:C.ink}}>
                    <div style={{flex:1}} className="flex items-center gap-1">{go?<ChevronDown size={13}/>:<ChevronRight size={13}/>}{g.name}</div>
                    <div style={{width:90,textAlign:"right"}}>{Math.round(g.total)}</div>
                    <div style={{width:120,textAlign:"right",color:C.muted}}>{Math.round(g.total/pGrand*100)}%</div>
                  </div>
                  {go && subs.map(s=>(
                    <div key={s.name} className="flex items-center" style={{padding:"5px 10px 5px 46px",borderTop:"1px solid #F8FAFC",fontSize:12,color:C.muted}}>
                      <div style={{flex:1}}>{s.name}</div><div style={{width:90,textAlign:"right"}}>{Math.round(s.value)}</div><div style={{width:120,textAlign:"right"}}>{Math.round(s.value/pGrand*100)}%</div>
                    </div>))}
                </div>);})}
            </div>);})}
          {fams.length===0 && <div style={{padding:18,textAlign:"center",color:C.muted}}>No product effort in this period.</div>}
        </div>
      </div>
      <p style={{fontSize:11.5,color:C.muted,marginTop:14}}>{fwMode?"Forward = planned story points for epics overlapping the period; an epic's points split evenly across its roles / sub-groups.":"Retrospective = logged hours, attributed to each item's product sub-group (inherited from its parent epic where the worklog sits on a story, task or bug)."}</p>
    </div>
  );
}

function StrategyMap({onOpen}){
  const [view,setView]=useState("okr");
  const [pillarF,setPillarF]=useState(new Set());
  const [buMode,setBuMode]=useState("delivering");
  const [buF,setBuF]=useState(new Set());
  const [pmode,setPmode]=useState("all");
  const [showEmpty,setShowEmpty]=useState(true);
  const snap=parse(DATA.snapshot);
  const qStart=(d)=>{const x=new Date(d);x.setMonth(Math.floor(x.getMonth()/3)*3,1);x.setHours(0,0,0,0);return x;};
  const qEnd=(s)=>{const x=new Date(s);x.setMonth(x.getMonth()+3,0);return x;};
  const cs=qStart(snap);
  const [cStart,setCStart]=useState(cs.toISOString().slice(0,10));
  const [cEnd,setCEnd]=useState(qEnd(cs).toISOString().slice(0,10));
  let pStart=null,pEnd=null,plabel="all dates";
  if(pmode==="current"){pStart=cs;pEnd=qEnd(cs);plabel="current quarter";}
  else if(pmode==="next"){const n=new Date(cs);n.setMonth(n.getMonth()+3,1);pStart=n;pEnd=qEnd(n);plabel="next quarter";}
  else if(pmode==="custom"){pStart=parse(cStart);pEnd=parse(cEnd);plabel="selected range";}
  const [expanded,setExpanded]=useState(()=>new Set());
  const [modal,setModal]=useState(null);
  const tog=(set,setter,v)=>{const n=new Set(set);n.has(v)?n.delete(v):n.add(v);setter(n);};
  const texp=(k)=>{const n=new Set(expanded);n.has(k)?n.delete(k):n.add(k);setExpanded(n);};
  const items=DATA.issues.filter(i=>!i.unplanned);
  const allBUs=[...new Set(items.map(i=>i.bu))].sort();
  const pillars=[...new Set(DATA.okrAll.map(o=>o.pillar))];
  const buMatch=(i)=>{ if(!buF.size)return true; const del=buF.has(i.bu); const rec=(i.recvBUs||[]).some(b=>buF.has(b)); return buMode==="delivering"?del:buMode==="receiving"?rec:(del||rec); };
  const overlap=(i)=>{ if(!pStart||!pEnd)return true; const s=parse(i.start),d=parse(i.due); return s&&d&&s<=pEnd&&d>=pStart; };
  const passed=items.filter(i=>buMatch(i)&&overlap(i));
  const itemsUnder=(pre)=> passed.filter(i=>i.okrChain && pre.every((p,idx)=>i.okrChain[idx]===p));
  const tax={}; DATA.okrAll.forEach(o=>{ const f=(tax[o.pillar]=tax[o.pillar]||{}); const ob=(f[o.focus]=f[o.focus]||{}); const k=(ob[o.objective]=ob[o.objective]||{}); k[o.kr]=true; });

  const TYPES=[["Major Theme","Themes",C.navy],["Initiative","Inits",C.accent],["Epic","Epics","#0EA5E9"]];
  const Badges=({arr})=> <span className="flex items-center gap-1.5">{TYPES.map(([t,l,c])=>{const n=arr.filter(x=>x.type===t).length; const on=n>0; return <span key={t} style={{background:on?c+"14":"#F8FAFC",color:on?c:"#CBD5E1",border:"1px solid "+(on?c+"55":"#EEF2F9"),borderRadius:5,padding:"1px 7px",fontSize:11,fontWeight:700}}>{n} {l}</span>;})}</span>;

  function node(label, child, pre, level){
    const path=[...pre,label]; const arr=itemsUnder(path); const isLeaf=level===3; const zero=arr.length===0;
    if(zero && !showEmpty) return null;
    const key=path.join("||"); const open=expanded.has(key);
    return (<React.Fragment key={key}>
      <div className="flex items-center justify-between gap-3" style={{padding:"8px 12px",paddingLeft:12+level*18,borderTop:"1px solid #F1F5F9",cursor:"pointer",opacity:zero?0.5:1}}
        onClick={()=> isLeaf?setModal({title:label,sub:path.slice(0,-1).join("  ›  "),arr}):texp(key)}>
        <div className="flex items-center gap-1" style={{minWidth:0,fontWeight:level<2?700:600,fontSize:level===0?13.5:12.5,color:level===0?C.navy:C.ink}}>
          {!isLeaf?(open?<ChevronDown size={14}/>:<ChevronRight size={14}/>):<span style={{width:14,display:"inline-block"}}/>}
          <span style={{overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{label}</span>
        </div>
        <span className="flex items-center gap-2" style={{flexShrink:0}} onClick={(e)=>{e.stopPropagation();setModal({title:label,sub:path.slice(0,-1).join("  ›  "),arr});}}><Badges arr={arr}/></span>
      </div>
      {!isLeaf&&open&&Object.keys(child).sort().map(cl=>node(cl,child[cl],path,level+1))}
    </React.Fragment>);
  }

  const pgaGroups=DATA.pgaAll.map(p=>({key:p,arr:passed.filter(i=>i.pga===p)})).filter(g=>showEmpty||g.arr.length>0);
  const shownPillars=pillars.filter(p=>pillarF.size===0||pillarF.has(p));

  return (
    <div style={{background:C.card,borderRadius:"0 8px 8px 8px",border:"1px solid "+C.border,padding:18}}>
      <div className="flex flex-wrap items-center gap-3" style={{marginBottom:8}}>
        <SectionTitle>Strategic alignment</SectionTitle>
        <div className="flex" style={{border:"1px solid "+C.border,borderRadius:8,overflow:"hidden"}}>
          {[["okr","OKR / Scorecard"],["pga","Prioritized Growth Area"]].map(([k,l])=>(<button key={k} onClick={()=>setView(k)} style={{border:"none",cursor:"pointer",padding:"7px 14px",fontSize:12.5,fontWeight:700,background:view===k?C.navy:"#fff",color:view===k?"#fff":C.muted}}>{l}</button>))}
        </div>
      </div>
      <p style={{fontSize:12.5,color:C.muted,margin:"0 0 12px"}}>Major themes, initiatives and epics mapped to each {view==="okr"?"objective & key result":"growth area"} — including elements with nothing mapped. Counts respect the BU and period filters; click a row (or its badges) to list and open the items.</p>
      <div className="flex flex-wrap items-center gap-3" style={{marginBottom:10}}>
        {view==="okr" && <FilterGroup label="Scorecard" opts={pillars} sel={pillarF} onToggle={v=>tog(pillarF,setPillarF,v)} shorten/>}
        <div className="flex items-center gap-1.5 flex-wrap">
          <span style={{fontSize:11.5,color:C.muted,fontWeight:600}}>BU:</span>
          <div className="flex" style={{border:"1px solid "+C.border,borderRadius:7,overflow:"hidden"}}>
            {[["delivering","Delivering"],["receiving","Receiving"],["both","Both"]].map(([k,l])=>(<button key={k} onClick={()=>setBuMode(k)} style={{border:"none",cursor:"pointer",padding:"4px 9px",fontSize:11,fontWeight:700,background:buMode===k?C.navy:"#fff",color:buMode===k?"#fff":C.muted}}>{l}</button>))}
          </div>
          {allBUs.map(o=>{const a=buF.has(o); return <button key={o} onClick={()=>tog(buF,setBuF,o)} style={{border:"1px solid "+(a?C.accent:C.border),background:a?C.accent+"1A":"#fff",color:a?C.accent:C.muted,borderRadius:14,padding:"3px 10px",fontSize:11.5,cursor:"pointer",fontWeight:600}}>{o}</button>;})}
        </div>
        {(pillarF.size||buF.size)>0 && <button onClick={()=>{setPillarF(new Set());setBuF(new Set());}} style={{fontSize:12,color:C.accent,background:"none",border:"none",cursor:"pointer"}}>clear</button>}
      </div>
      <div className="flex flex-wrap items-center gap-2" style={{marginBottom:14}}>
        <span style={{fontSize:11.5,color:C.muted,fontWeight:600}}>Active in period:</span>
        {[["all","All dates"],["current","Current quarter"],["next","Next quarter"],["custom","Custom"]].map(([k,l])=>(<button key={k} onClick={()=>setPmode(k)} style={{border:"1px solid "+(pmode===k?C.accent:C.border),color:pmode===k?C.accent:C.muted,background:"#fff",borderRadius:6,padding:"4px 10px",fontSize:11.5,cursor:"pointer",fontWeight:600}}>{l}</button>))}
        {pmode==="custom"&&<span className="flex items-center gap-1"><input type="date" value={cStart} onChange={e=>setCStart(e.target.value)} style={{border:"1px solid "+C.border,borderRadius:6,padding:"3px 6px",fontSize:12}}/><span style={{color:C.muted}}>→</span><input type="date" value={cEnd} onChange={e=>setCEnd(e.target.value)} style={{border:"1px solid "+C.border,borderRadius:6,padding:"3px 6px",fontSize:12}}/></span>}
        <div style={{width:1,height:18,background:C.border,margin:"0 4px"}}/>
        <button onClick={()=>setShowEmpty(!showEmpty)} style={{border:"1px solid "+C.border,background:"#fff",color:C.muted,borderRadius:14,padding:"3px 10px",fontSize:11.5,cursor:"pointer",fontWeight:600}}>{showEmpty?"Hide empty":"Show empty"}</button>
      </div>

      {view==="okr" ? shownPillars.map(p=>(
        <div key={p} style={{border:"1px solid "+C.border,borderRadius:8,overflow:"hidden",marginBottom:10}}>{node(p,tax[p],[],0)}</div>
      )) : (
        <div style={{border:"1px solid "+C.border,borderRadius:8,overflow:"hidden"}}>
          {pgaGroups.map(g=>{const zero=g.arr.length===0; return (
            <div key={g.key} onClick={()=>setModal({title:g.key,sub:"Prioritized growth area",arr:g.arr})} className="flex items-center justify-between gap-3" style={{padding:"10px 12px",borderTop:"1px solid #F1F5F9",cursor:"pointer",opacity:zero?0.5:1}}>
              <span style={{fontWeight:700,fontSize:13}}>{g.key}</span><Badges arr={g.arr}/>
            </div>);})}
        </div>
      )}

      {modal && <div onClick={()=>setModal(null)} style={{position:"fixed",inset:0,background:"rgba(15,23,42,0.35)",zIndex:55,display:"flex",alignItems:"flex-start",justifyContent:"center",padding:"6vh 16px"}}>
        <div onClick={e=>e.stopPropagation()} style={{width:560,maxWidth:"100%",maxHeight:"82vh",display:"flex",flexDirection:"column",background:"#fff",borderRadius:12,boxShadow:"0 20px 50px rgba(0,0,0,0.25)",overflow:"hidden"}}>
          <div className="flex justify-between items-start" style={{padding:"16px 18px 10px"}}>
            <div><div style={{fontSize:16,fontWeight:800,color:C.navy}}>{modal.title}</div>{modal.sub&&<div style={{fontSize:12,color:C.muted,marginTop:2}}>{modal.sub}</div>}</div>
            <button onClick={()=>setModal(null)} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={20}/></button>
          </div>
          <div style={{padding:"0 18px 14px",overflowY:"auto"}}>
            {modal.arr.length===0 && <div style={{padding:18,textAlign:"center",color:C.muted}}>Nothing mapped here yet.</div>}
            {TYPES.map(([t,l,c])=>{const a=modal.arr.filter(x=>x.type===t); if(!a.length)return null; return (
              <div key={t} style={{marginBottom:8}}>
                <div style={{fontSize:11.5,fontWeight:700,color:c,margin:"6px 0 2px"}}>{l} ({a.length})</div>
                {a.map(it=><div key={it.key} onClick={()=>{setModal(null);onOpen(it);}} className="flex items-center justify-between gap-3" style={{padding:"7px 0",borderBottom:"1px solid #F1F5F9",cursor:"pointer"}}>
                  <span className="flex items-center gap-2" style={{minWidth:0}}><RagDot rag={ragMap[it.key].rag} size={9}/><span style={{fontWeight:600,fontSize:13}}>{it.summary}</span></span>
                  <span style={{flexShrink:0,fontSize:11.5,color:C.muted}}>{it.key} · {it.bu} · due {fmt(it.due)}</span>
                </div>)}
              </div>);})}
          </div>
        </div>
      </div>}
    </div>
  );
}
const BUCOL={"C&G":"#2E6BFF","Banking":"#0EA5E9","Insurance":"#8B5CF6","Data Estate":"#16A34A","Platform Engineering":"#F59E0B","DC&I":"#DB2777"};
const buColor=(b)=>BUCOL[b]||"#94A3B8";
const typeShortV={"Major Theme":"Theme","Initiative":"Initiative","Epic":"Epic"};

function DepViz({onOpen}){
  const themes=DATA.issues.filter(i=>i.type==="Major Theme"&&!i.unplanned);
  const [trail,setTrail]=useState([themes[0]?themes[0].key:null]);
  const [dir,setDir]=useState("out"); // out | in | both
  const [hover,setHover]=useState(null);
  const focusKey=trail[trail.length-1];
  const focus=issuesByKey[focusKey];
  const W=780,H=540;
  const svgRef=useRef(null), dragRef=useRef(null), wrapRef=useRef(null), hoverRef=useRef(null);
  const [tip,setTip]=useState(null);
  const [,tick]=useState(0);

  // boundary = focus + all descendants
  const boundary=useMemo(()=>new Set(descKeys(focusKey)),[focusKey]);
  const kids=DATA.issues.filter(i=>i.parent===focusKey);
  const childContaining=(key)=>{ let c=issuesByKey[key]; while(c&&c.parent!==focusKey&&c.key!==focusKey){ c=issuesByKey[c.parent]; } return (c&&c.key!==focusKey)?c.key:focusKey; };

  // external dependency edges (relative to the current boundary)
  const extEdges=useMemo(()=>{
    const out=[];
    DATA.deps.forEach(d=>{
      const sIn=boundary.has(d.src), tIn=boundary.has(d.tgt);
      if(sIn&&!tIn&&(dir==="out"||dir==="both")) out.push({id:d.id+"-o",inner:childContaining(d.src),ext:d.tgt,extBU:d.tgtBU,extSum:d.tgtSum,type:d.type,critical:d.critical,direction:"out",rawSrc:d.src});
      if(tIn&&!sIn&&(dir==="in"||dir==="both"))  out.push({id:d.id+"-i",inner:childContaining(d.tgt),ext:d.src,extBU:d.srcBU,extSum:d.srcSum,type:d.type,critical:d.critical,direction:"in",rawSrc:d.tgt});
    });
    return out;
  },[boundary,dir,focusKey]);

  // build graph nodes + links (stable per focus/dir so d3 can mutate x/y)
  const graph=useMemo(()=>{
    const nodes=[], links=[], byId={};
    const addNode=(id,kind,label,bu,r,extra)=>{ if(byId[id])return byId[id]; const n={id,kind,label,bu,r,...extra,x:W/2+(Math.random()-0.5)*120,y:H/2+(Math.random()-0.5)*120}; byId[id]=n; nodes.push(n); return n; };
    addNode(focusKey,"focus",focus?focus.summary:focusKey,focus&&focus.bu,36,{item:focus});
    kids.forEach(k=>{ addNode(k.key,"child",k.summary,k.bu,24,{item:k}); links.push({source:focusKey,target:k.key,kind:"child"}); });
    // count deps per external target for sizing
    const cnt={}; extEdges.forEach(e=>cnt[e.ext]=(cnt[e.ext]||0)+1);
    extEdges.forEach(e=>{
      const en=addNode(e.ext,"ext",e.extSum,e.extBU,16+Math.min(12,(cnt[e.ext]-1)*4),{item:issuesByKey[e.ext]});
      // ensure inner child node exists (it should, but if inner===focus link to focus)
      const innerId=e.inner;
      if(innerId!==focusKey && !byId[innerId]){ const it=issuesByKey[innerId]; addNode(innerId,"child",it?it.summary:innerId,it&&it.bu,24,{item:it}); links.push({source:focusKey,target:innerId,kind:"child"}); }
      links.push({source:innerId,target:e.ext,kind:"dep",critical:e.critical,direction:e.direction,type:e.type});
    });
    return {nodes,links};
  },[focusKey,dir]);

  useEffect(()=>{
    const {nodes,links}=graph;
    const sim=d3.forceSimulation(nodes)
      .force("charge",d3.forceManyBody().strength(-340))
      .force("link",d3.forceLink(links).id(d=>d.id).distance(l=>l.kind==="child"?92:165).strength(l=>l.kind==="child"?0.5:0.35))
      .force("center",d3.forceCenter(W/2,H/2))
      .force("collide",d3.forceCollide(d=>d.r+10))
      .force("x",d3.forceX(W/2).strength(0.04)).force("y",d3.forceY(H/2).strength(0.06))
      .on("tick",()=>tick(t=>t+1));
    // pin focus near centre
    const f=nodes.find(n=>n.kind==="focus"); if(f){ f.fx=W/2; f.fy=H/2; }
    const id=setTimeout(()=>{ if(f){ f.fx=null; f.fy=null; } },1200);
    return ()=>{ clearTimeout(id); sim.stop(); };
  },[graph]);

  const toPt=(e)=>{ const svg=svgRef.current; const p=svg.createSVGPoint(); p.x=e.clientX; p.y=e.clientY; const m=svg.getScreenCTM(); const r=p.matrixTransform(m.inverse()); return [r.x,r.y]; };
  const onDown=(e,n)=>{ e.stopPropagation(); dragRef.current=n; const [x,y]=toPt(e); n.fx=x; n.fy=y; tick(t=>t+1); try{e.target.setPointerCapture(e.pointerId);}catch(_){} };
  const onMove=(e)=>{ const n=dragRef.current; if(n){ const [x,y]=toPt(e); n.fx=x; n.fy=y; tick(t=>t+1); }
    if(hoverRef.current&&wrapRef.current){ const r=wrapRef.current.getBoundingClientRect(); const cx=e.clientX-r.left, cy=e.clientY-r.top; setTip(tp=>tp?{...tp,x:cx,y:cy}:tp); } };
  const nodeEnter=(e,n)=>{ hoverRef.current=n.id; setHover(n.id); const r=wrapRef.current.getBoundingClientRect(); setTip({node:n,x:e.clientX-r.left,y:e.clientY-r.top}); };
  const nodeLeave=()=>{ hoverRef.current=null; setHover(null); setTip(null); };
  const onUp=()=>{ const n=dragRef.current; if(n&&n.kind!=="focus"){ n.fx=null; n.fy=null; } dragRef.current=null; };

  const drill=(k)=>{ if(issuesByKey[k]) setTrail(t=>[...t,k]); };
  const {nodes,links}=graph;
  const linkColor=(l)=> l.kind==="child"?"#CBD5E1":(l.critical?RAG.Red:"#94A3B8");

  const extList=extEdges.slice().sort((a,b)=>Number(b.critical)-Number(a.critical));

  return (
    <div>
      <SectionTitle>Dependency explorer</SectionTitle>
      <p style={{fontSize:12.5,color:C.muted,margin:"2px 0 12px"}}>Start on a major theme to see everything it depends on <b>outside itself</b>. Click an initiative (or any node) to re-centre and reveal that level's external dependencies, down to epic. Drag nodes to pull the map around.</p>
      <div className="flex flex-wrap items-center gap-3" style={{marginBottom:10}}>
        <div className="flex items-center gap-1.5"><span style={{fontSize:11.5,color:C.muted,fontWeight:600}}>Start:</span>
          {themes.map(t=><button key={t.key} onClick={()=>setTrail([t.key])} style={{border:"1px solid "+(trail[0]===t.key&&trail.length===1?C.accent:C.border),background:trail[0]===t.key&&trail.length===1?C.accent+"1A":"#fff",color:trail[0]===t.key&&trail.length===1?C.accent:C.muted,borderRadius:14,padding:"3px 10px",fontSize:11.5,cursor:"pointer",fontWeight:600}}>{t.summary}</button>)}
        </div>
        <div style={{flex:1}}/>
        <div className="flex" style={{border:"1px solid "+C.border,borderRadius:7,overflow:"hidden"}}>
          {[["out","Depends on"],["in","Depended on by"],["both","Both"]].map(([k,l])=>(<button key={k} onClick={()=>setDir(k)} style={{border:"none",cursor:"pointer",padding:"5px 11px",fontSize:11.5,fontWeight:700,background:dir===k?C.navy:"#fff",color:dir===k?"#fff":C.muted}}>{l}</button>))}
        </div>
      </div>
      <div className="flex items-center gap-1.5 flex-wrap" style={{marginBottom:8,fontSize:12}}>
        {trail.map((k,i)=>{const it=issuesByKey[k]; return <span key={k+i} className="flex items-center gap-1.5">{i>0&&<span style={{color:"#CBD5E1"}}>›</span>}<button onClick={()=>setTrail(t=>t.slice(0,i+1))} style={{background:"none",border:"none",cursor:"pointer",padding:0,fontWeight:i===trail.length-1?800:600,color:i===trail.length-1?C.navy:C.accent}}>{it?it.summary:k}</button></span>;})}
      </div>
      <div className="flex flex-wrap gap-3">
        <div ref={wrapRef} style={{flex:"1 1 520px",minWidth:340,position:"relative"}}>
        <div style={{border:"1px solid "+C.border,borderRadius:12,background:"radial-gradient(120% 120% at 50% 0%, #FBFCFE 0%, #EEF2FB 100%)",overflow:"hidden"}}>
          <svg ref={svgRef} viewBox={"0 0 "+W+" "+H} style={{width:"100%",display:"block",touchAction:"none"}} onPointerMove={onMove} onPointerUp={onUp} onPointerLeave={onUp}>
            <defs>
              <filter id="dvshadow" x="-40%" y="-40%" width="180%" height="180%"><feDropShadow dx="0" dy="3" stdDeviation="3" floodColor="#1E293B" floodOpacity="0.28"/></filter>
              <radialGradient id="gfocus" cx="34%" cy="28%" r="80%"><stop offset="0%" stopColor="#3B5BD9"/><stop offset="100%" stopColor={C.navy}/></radialGradient>
              <radialGradient id="gchild" cx="34%" cy="28%" r="80%"><stop offset="0%" stopColor="#6BA6FF"/><stop offset="100%" stopColor={C.accent}/></radialGradient>
              <marker id="dvarrow" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="7" markerHeight="7" orient="auto-start-reverse"><path d="M0 0L10 5L0 10z" fill="#94A3B8"/></marker>
              <marker id="dvarrowR" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="7" markerHeight="7" orient="auto-start-reverse"><path d="M0 0L10 5L0 10z" fill={RAG.Red}/></marker>
            </defs>
            {links.map((l,i)=>{const s=l.source,t=l.target; if(!s.x||!t.x)return null; const dep=l.kind==="dep"; const hl=hover&&(s.id===hover||t.id===hover);
              return <line key={i} x1={s.x} y1={s.y} x2={t.x} y2={t.y} stroke={linkColor(l)} strokeWidth={dep?(l.critical?2.4:1.6):1.2} strokeDasharray={dep&&l.direction==="in"?"5 4":undefined} strokeOpacity={hover?(hl?0.95:0.18):(dep?0.7:0.45)} markerEnd={dep?(l.critical?"url(#dvarrowR)":"url(#dvarrow)"):undefined}/>;})}
            {nodes.map(n=>{const isF=n.kind==="focus",isC=n.kind==="child"; const fill=isF?"url(#gfocus)":isC?"url(#gchild)":buColor(n.bu); const rag=n.item?ragMap[n.item.key]:null; const hl=hover===n.id;
              return <g key={n.id} transform={"translate("+(n.x||W/2)+","+(n.y||H/2)+")"} style={{cursor:"pointer"}}
                  onPointerDown={(e)=>onDown(e,n)} onPointerEnter={(e)=>nodeEnter(e,n)} onPointerLeave={nodeLeave}
                  onClick={(e)=>{e.stopPropagation(); if(dragRef.current)return; (isF?onOpen(n.item):drill(n.id));}}
                  onDoubleClick={()=>n.item&&onOpen(n.item)}>
                <circle r={n.r} fill={fill} filter="url(#dvshadow)" stroke="#fff" strokeWidth={2} style={{transform:hl?"scale(1.08)":"scale(1)",transition:"transform .12s"}}/>
                {rag&&!isF&&<circle r={4.5} cx={n.r*0.62} cy={-n.r*0.62} fill={RAG[rag.rag]} stroke="#fff" strokeWidth={1.5}/>}
                <text textAnchor="middle" y={n.r+13} style={{fontSize:isF?12:11,fontWeight:isF?800:600,fill:C.ink,paintOrder:"stroke",stroke:"#fff",strokeWidth:3,strokeLinejoin:"round"}}>{n.label.length>22?n.label.slice(0,21)+"…":n.label}</text>
                {n.bu&&<text textAnchor="middle" y={n.r+25} style={{fontSize:9.5,fontWeight:700,fill:buColor(n.bu),paintOrder:"stroke",stroke:"#fff",strokeWidth:3,strokeLinejoin:"round"}}>{n.bu}</text>}
              </g>;})}
          </svg>
        </div>
        {tip&&tip.node.item&&(()=>{const it=tip.node.item; const p=pathOf(it.key); const rg=ragMap[it.key]; const flip=tip.x>360;
          return <div style={{position:"absolute",left:tip.x,top:tip.y,transform:"translate("+(flip?"calc(-100% - 14px)":"14px")+", 14px)",width:230,background:"#fff",border:"1px solid "+C.border,borderRadius:10,boxShadow:"0 12px 30px rgba(15,23,42,0.22)",padding:11,pointerEvents:"none",zIndex:5}}>
            <div style={{fontSize:13,fontWeight:800,lineHeight:1.2}}>{it.summary}</div>
            <div style={{fontSize:10.5,color:C.muted,marginTop:1}}>{typeShortV[it.type]||it.type} · {it.key}</div>
            <div className="flex items-center gap-1.5" style={{margin:"7px 0"}}><Chip label={it.bu} color={buColor(it.bu)}/><span className="flex items-center gap-1" style={{fontSize:11,fontWeight:700,color:RAG[rg.rag]}}><RagDot rag={rg.rag} size={8}/>{it.status}</span></div>
            <div style={{fontSize:11.5}}><span style={{color:C.muted}}>Due: </span>{fmt(it.due)}</div>
            <div style={{marginTop:7,borderTop:"1px solid #F1F5F9",paddingTop:6}}>
              {p.map((a,idx)=><div key={a.key} style={{fontSize:10.5,paddingLeft:idx*8,color:idx===p.length-1?C.ink:C.muted,fontWeight:idx===p.length-1?700:500}}>{typeShortV[a.type]||a.type}: {a.summary}</div>)}
            </div>
            <div style={{fontSize:10,color:"#94A3B8",marginTop:6}}>{tip.node.kind==="focus"?"click to open detail":"click to drill in · double-click to open"}</div>
          </div>;})()}
        </div>
        <div style={{flex:"1 1 230px",minWidth:230}}>
          <div style={{border:"1px solid "+C.border,borderRadius:10,padding:12}}>
            <div style={{fontSize:11,color:C.muted}}>{focus?typeShortV[focus.type]||focus.type:""} in focus</div>
            <div style={{fontSize:15,fontWeight:800}}>{focus?focus.summary:"—"}</div>
            <div className="flex items-center gap-1.5" style={{marginTop:4}}>{focus&&<><Chip label={focus.bu} color={buColor(focus.bu)}/><Chip label={"RAG "+ragMap[focusKey].rag} color={RAG[ragMap[focusKey].rag]} solid/></>}</div>
            <div className="flex gap-4" style={{margin:"10px 0"}}><Stat n={kids.length} l={focus&&focus.type==="Major Theme"?"initiatives":"epics"}/><Stat n={extEdges.length} l="external links"/><Stat n={extEdges.filter(e=>e.critical).length} l="critical"/></div>
            <div style={{fontSize:11.5,fontWeight:700,color:C.navy,margin:"4px 0"}}>External dependencies</div>
            <div style={{maxHeight:300,overflowY:"auto"}}>
              {extList.length===0&&<div style={{fontSize:12,color:C.muted}}>None outside this {focus?focus.type.toLowerCase():"item"}.</div>}
              {extList.map(e=>(<div key={e.id} onMouseEnter={()=>setHover(e.ext)} onMouseLeave={()=>setHover(null)} onClick={()=>issuesByKey[e.ext]&&onOpen(issuesByKey[e.ext])} style={{padding:"6px 0",borderBottom:"1px solid #F1F5F9",cursor:"pointer"}}>
                <div className="flex items-center gap-1.5" style={{fontSize:11.5}}><span style={{width:8,height:8,borderRadius:2,background:buColor(e.extBU)}}/><span style={{fontWeight:700}}>{e.extSum}</span>{e.critical&&<Chip label="critical" color={RAG.Red}/>}</div>
                <div style={{fontSize:10.5,color:C.muted,marginLeft:14}}>{e.direction==="out"?"depends on":"depended on by"} · {e.extBU} · via {issuesByKey[e.inner]?issuesByKey[e.inner].summary:e.inner}</div>
              </div>))}
            </div>
          </div>
          <div className="flex flex-wrap items-center gap-2" style={{marginTop:8,fontSize:11,color:C.muted}}>
            <span className="flex items-center gap-1"><span style={{width:10,height:10,borderRadius:999,background:C.navy}}/>focus</span>
            <span className="flex items-center gap-1"><span style={{width:10,height:10,borderRadius:999,background:C.accent}}/>inside (drill)</span>
            <span className="flex items-center gap-1"><span style={{width:10,height:10,borderRadius:999,background:"#94A3B8"}}/>external (by BU)</span>
            <span className="flex items-center gap-1"><span style={{width:14,height:2,background:RAG.Red,display:"inline-block"}}/>critical</span>
          </div>
        </div>
      </div>
    </div>
  );
}

const Tile=({label,value,sub,accent,onClick})=>(<div onClick={onClick} style={{background:C.card,border:"1px solid "+C.border,borderRadius:10,padding:"12px 16px",minWidth:150,borderTop:"3px solid "+(accent||C.navy),cursor:onClick?"pointer":"default",position:"relative"}}>{onClick&&<span style={{position:"absolute",top:7,right:9,color:"#94A3B8",fontSize:12}}>↗</span>}<div style={{fontSize:11.5,color:C.muted,fontWeight:600,textTransform:"uppercase",letterSpacing:0.4}}>{label}</div><div style={{fontSize:24,fontWeight:800,marginTop:2}}>{value}</div><div style={{fontSize:11,color:C.muted}}>{sub}</div></div>);
const Toggle=({on,set,label})=>(<button onClick={set} className="flex items-center gap-2" style={{background:"#fff",border:"1px solid "+C.border,borderRadius:20,padding:"5px 12px 5px 6px",cursor:"pointer",fontSize:12.5,fontWeight:600,color:C.ink}}><span style={{width:30,height:17,borderRadius:999,background:on?C.accent:"#CBD5E1",position:"relative"}}><span style={{position:"absolute",top:2,left:on?15:2,width:13,height:13,borderRadius:999,background:"#fff"}}/></span>{label}</button>);
const FilterGroup=({label,opts,sel,onToggle,colorMap,shorten})=>(<div className="flex items-center gap-1.5 flex-wrap"><span style={{fontSize:11.5,color:C.muted,fontWeight:600}}>{label}:</span>{opts.map(o=>{const active=sel.has(o); const col=colorMap?colorMap[o]:C.accent; const lab=shorten?(String(o).split(": ").slice(1).join(": ")||o):o; return <button key={o} title={o} onClick={()=>onToggle(o)} style={{border:"1px solid "+(active?col:C.border),background:active?col+"1A":"#fff",color:active?col:C.muted,borderRadius:14,padding:"3px 10px",fontSize:11.5,cursor:"pointer",fontWeight:600}}>{lab}</button>;})}</div>);
const Legend=()=>(<div className="flex flex-wrap items-center gap-4" style={{marginTop:12,paddingTop:10,borderTop:"1px solid "+C.border,fontSize:11.5,color:C.muted}}><span className="flex items-center gap-1.5"><Star size={12} color={C.accent} fill={C.accent}/> exec priority</span><span className="flex items-center gap-1.5"><RagDot rag="Green"/> on track <RagDot rag="Amber"/> at risk <RagDot rag="Red"/> off track <span style={{fontStyle:"italic"}}>(computed)</span></span><span className="flex items-center gap-1.5"><Boxes size={12} color={C.accent}/> products — click to drill</span><span className="flex items-center gap-1.5"><GitBranch size={12} color="#B45309"/> dependencies — click for detail</span><span className="flex items-center gap-1.5"><TrendingUp size={12} color={RAG.Green}/> improving <TrendingDown size={12} color={RAG.Red}/> deteriorating <Minus size={12} color={C.muted}/> stable — RAG trend vs last period</span><span className="flex items-center gap-1.5"><span style={{background:C.navy,color:"#fff",borderRadius:3,padding:"0 4px",fontSize:9,fontWeight:700}}>Del</span> delivering BU <span style={{background:"#0EA5E9",color:"#fff",borderRadius:3,padding:"0 4px",fontSize:9,fontWeight:700}}>Rec</span> receiving BU (depends on this)</span><span className="flex items-center gap-1.5"><span style={{width:9,height:9,borderRadius:2,background:ROLE["Double Down"],display:"inline-block"}}/> role % = share of the item's product sub-groups in that role</span><span className="flex items-center gap-1.5"><span style={{width:2,height:12,background:"#FCA5A5",display:"inline-block"}}/> today</span></div>);
const SectionTitle=({children,style})=><div style={{fontSize:14.5,fontWeight:700,color:C.navy,...style}}>{children}</div>;
const Stat=({n,l})=><div><div style={{fontSize:20,fontWeight:800,color:C.navy}}>{n}</div><div style={{fontSize:10.5,color:C.muted}}>{l}</div></div>;
const Panel=({title,children})=>(<div style={{flex:"1 1 280px",minWidth:270,border:"1px solid "+C.border,borderRadius:8,padding:12}}><div style={{fontSize:13,fontWeight:700,marginBottom:6}}>{title}</div>{children}</div>);
const KeyList=({data,colorMap})=>(<div className="flex flex-wrap gap-x-3 gap-y-1" style={{marginTop:6}}>{data.map(d=><span key={d.name} className="flex items-center gap-1" style={{fontSize:11.5}}><span style={{width:9,height:9,borderRadius:2,background:colorMap[d.name]||"#CBD5E1"}}/>{d.name} · <b>{d.value}</b></span>)}</div>);
const Table=({head,rows})=>(<div style={{overflowX:"auto",marginTop:8}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:12.5}}><thead><tr>{head.map((h,i)=><th key={i} style={{textAlign:"left",padding:"7px 10px",color:C.muted,fontWeight:600,borderBottom:"2px solid "+C.border,whiteSpace:"nowrap"}}>{h}</th>)}</tr></thead><tbody>{rows.map((r,i)=><tr key={i} style={{borderBottom:"1px solid #F1F5F9"}}>{r.map((c,j)=><td key={j} style={{padding:"7px 10px",verticalAlign:"top"}}>{c}</td>)}</tr>)}</tbody></table></div>);
function Drawer({item,rg,cr,out,inc,onClose,onJump}){
  const Row=({k,v})=><div className="flex justify-between gap-3" style={{padding:"6px 0",borderBottom:"1px solid #F1F5F9",fontSize:12.5}}><span style={{color:C.muted}}>{k}</span><span style={{fontWeight:600,textAlign:"right"}}>{v}</span></div>;
  return (<div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(15,23,42,0.35)",zIndex:50}}>
    <div onClick={e=>e.stopPropagation()} style={{position:"absolute",right:0,top:0,bottom:0,width:390,maxWidth:"92vw",background:"#fff",padding:20,overflowY:"auto",boxShadow:"-8px 0 24px rgba(0,0,0,0.12)"}}>
      <div className="flex justify-between items-start"><div><div style={{fontSize:11,color:C.muted}}>{item.key} · {item.type}</div><div style={{fontSize:17,fontWeight:800}}>{item.summary}</div></div><button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={20}/></button></div>
      <div className="flex flex-wrap gap-2" style={{margin:"10px 0 12px"}}>{item.execTop&&<Chip label="Exec priority" color={C.accent} solid/>}<Chip label={"RAG: "+rg.rag} color={RAG[rg.rag]} solid/><Chip label={item.gnb} color={GNBC[item.gnb]}/></div>
      <div style={{background:C.bg,borderRadius:8,padding:10,marginBottom:14,fontSize:12.5}}><div className="flex items-center gap-1.5" style={{fontWeight:700,marginBottom:4}}><AlertCircle size={14} color={RAG[rg.rag]}/> Why {rg.rag}</div><ul style={{margin:0,paddingLeft:16}}>{rg.reasons.map((x,i)=><li key={i}>{x}</li>)}</ul>{cr&&<div style={{marginTop:6,color:C.muted}}>Commentary: {cr.commentary}</div>}</div>
      <Row k="Status" v={item.status}/><Row k="Delivering BU" v={item.bu}/><Row k="Receiving BU(s)" v={(item.recvBUs&&item.recvBUs.length)?item.recvBUs.join(", "):"—"}/><Row k="Priority" v={item.priority}/><Row k="Start → Due" v={fmt(item.start)+" → "+fmt(item.due)}/><Row k="Story points" v={item.sp}/>
      <Row k="Portfolio roles" v={(()=>{const rd=roleDistFromSubs(item); return rd.length?rd.map(d=>d.role+" "+d.pct+"%").join(" · "):(item.roles.join(", ")||"—");})()}/><Row k="GNB / Retention" v={item.gnb}/><Row k="Growth area" v={item.pga}/><Row k="OKR focus" v={item.focus}/><Row k="New / existing" v={item.newprod}/>
      <Row k="Product families" v={item.families.join(", ")||"—"}/><Row k="Sub-groups" v={item.subgroups.length}/>
      {out.length>0&&<><SectionTitle style={{marginTop:16,fontSize:13}}>Depends on (external)</SectionTitle>{out.map(d=><div key={d.id} onClick={()=>issuesByKey[d.tgt]&&onJump(issuesByKey[d.tgt])} style={{fontSize:12,padding:"5px 0",borderBottom:"1px solid #F1F5F9",cursor:issuesByKey[d.tgt]?"pointer":"default"}}><Chip label={d.type} color={d.critical?RAG.Red:C.muted}/> {d.tgtSum} <span style={{color:C.muted}}>({d.tgtBU})</span></div>)}</>}
      {inc.length>0&&<><SectionTitle style={{marginTop:16,fontSize:13}}>Depended on by ({inc.length})</SectionTitle>{inc.slice(0,10).map(d=><div key={d.id} style={{fontSize:12,padding:"5px 0",borderBottom:"1px solid #F1F5F9"}}>{d.srcSum} <span style={{color:C.muted}}>({d.srcBU})</span></div>)}</>}
    </div>
  </div>);
}

function OkrTip({tip}){
  const {x,y,pga,chain,focus,okr}=tip;
  const lines = (chain&&chain.length) ? chain : (focus&&focus!=="N/A" ? [focus] : (okr?[okr]:[]));
  return (
    <div style={{position:"fixed",left:x,top:y,zIndex:70,width:340,maxWidth:"92vw",background:"#fff",border:"1px solid "+C.border,borderRadius:10,boxShadow:"0 10px 30px rgba(0,0,0,0.18)",padding:12,fontSize:12,pointerEvents:"none"}}>
      <div style={{fontSize:10.5,color:C.muted,fontWeight:700,textTransform:"uppercase",letterSpacing:0.4,marginBottom:6}}>Objective &amp; key result</div>
      {pga&&pga!=="N/A"&&<div style={{marginBottom:8}}><span style={{color:C.muted}}>Growth area: </span><span style={{color:C.accent,fontWeight:700}}>{pga}</span></div>}
      {lines.length>0 ? lines.map((t,i)=>(
        <div key={i} style={{paddingLeft:i*14,marginBottom:4,position:"relative",lineHeight:1.35}}>
          {i>0&&<span style={{position:"absolute",left:i*14-9,top:1,color:"#CBD5E1"}}>&#8627;</span>}
          <span style={{fontWeight:i===lines.length-1?700:600,color:i===lines.length-1?C.ink:C.navy}}>{t}</span>
        </div>
      )) : <div style={{color:C.muted}}>No OKR mapped.</div>}
    </div>
  );
}

const EXECTOP = new Set(DATA.issues.filter(i=>i.type==="Major Theme"&&i.execTop).map(i=>i.key));
function hubItems(){
  const m={};
  DATA.deps.forEach(d=>{ if(!m[d.tgt]) m[d.tgt]={key:d.tgt,summary:d.tgtSum,bu:d.tgtBU,themes:new Set(),bus:new Set(),feedsExec:false,count:0};
    const x=m[d.tgt]; x.count++; if(d.srcTheme)x.themes.add(d.srcTheme); x.bus.add(d.srcBU); if(EXECTOP.has(d.srcTheme))x.feedsExec=true; });
  return Object.values(m).map(x=>({...x,themes:x.themes.size,bus:x.bus.size})).sort((a,b)=>b.themes-a.themes);
}

function KpiModal({which,execList,onClose,goTab,onOpen}){
  const META={
    exec:{title:"Exec deliverables",blurb:"Major themes flagged as executive priorities and tracked here.",tab:"roadmap",tabLabel:"View in Roadmap"},
    rag:{title:"RAG status — exec priorities",blurb:"Computed from delivery signals (status, due dates, slippage, dependencies). Click an item to see the full reasoning.",tab:"roadmap",tabLabel:"View in Roadmap"},
    blocked:{title:"Blocked items",blurb:"Items currently blocked, with escalation and revenue at risk.",tab:"actions",tabLabel:"View in Actions"},
    bottlenecks:{title:"Key bottlenecks",blurb:"Items three or more themes depend on — a slip here can stall several themes at once.",tab:"deps",tabLabel:"View in Dependencies"},
    slippage:{title:"Date slippage",blurb:"Items whose due date has moved, ranked by number of moves.",tab:"roadmap",tabLabel:"View in Roadmap"},
    unplanned:{title:"Unplanned work",blurb:"Reactive work (bugs, stories, tasks) carrying a Work Type of Unplanned, spread across business units and parent epics — not a single bucket.",tab:"invest",tabLabel:"View effort split in Investment"}
  }[which];
  const ItemRow=({it,right})=>(
    <div onClick={()=>it&&onOpen(it)} className="flex items-center justify-between gap-3" style={{padding:"9px 0",borderBottom:"1px solid #F1F5F9",cursor:it?"pointer":"default"}}>
      <span className="flex items-center gap-2" style={{minWidth:0}}>{it&&<RagDot rag={ragMap[it.key].rag} size={9}/>}<span style={{fontWeight:600,fontSize:13,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{(it?it.summary:"")}</span></span>
      <span style={{flexShrink:0,fontSize:12,color:C.muted,textAlign:"right"}}>{right}</span>
    </div>
  );
  let body=null;
  if(which==="exec") body=execList.map(t=><ItemRow key={t.key} it={t} right={<span>{t.bu} · due {fmt(t.due)} · <b style={{color:RAG[ragMap[t.key].rag]}}>{ragMap[t.key].rag}</b></span>}/>);
  else if(which==="rag") body=["Red","Amber","Green"].map(rag=>{const items=execList.filter(t=>ragMap[t.key].rag===rag); if(!items.length)return null;
    return <div key={rag} style={{marginBottom:10}}><div className="flex items-center gap-1.5" style={{fontWeight:700,fontSize:12.5,marginBottom:2}}><RagDot rag={rag}/>{rag} ({items.length})</div>
      {items.map(t=><div key={t.key} onClick={()=>onOpen(t)} style={{padding:"6px 0 6px 18px",borderBottom:"1px solid #F1F5F9",cursor:"pointer"}}><div style={{fontWeight:600,fontSize:13}}>{t.summary} <span style={{color:C.muted,fontWeight:400,fontSize:11.5}}>· {t.bu}</span></div><div style={{fontSize:11.5,color:C.muted}}>{ragMap[t.key].reasons.join(" · ")}</div></div>)}</div>;});
  else if(which==="blocked") body=DATA.blockers.map(b=><div key={b.item} onClick={()=>onOpen(issuesByKey[b.item])} className="flex items-center justify-between gap-3" style={{padding:"9px 0",borderBottom:"1px solid #F1F5F9",cursor:issuesByKey[b.item]?"pointer":"default"}}>
      <span style={{minWidth:0}}><div style={{fontWeight:600,fontSize:13}}>{b.summary} <span style={{color:C.muted,fontWeight:400,fontSize:11.5}}>· blocked by {b.blockedBy}</span></div><div style={{fontSize:11.5,color:C.muted}}>{b.consequence} · {b.revAtRisk}</div></span>
      <span style={{flexShrink:0,textAlign:"right"}}><div style={{fontWeight:700,color:b.days>60?RAG.Red:b.days>30?RAG.Amber:C.ink,fontSize:13}}>{b.days}d</div><Chip label={b.status} color={b.status==="Open"?RAG.Red:b.status==="Escalated"?RAG.Amber:RAG.Green}/></span></div>);
  else if(which==="bottlenecks") body=hubItems().filter(b=>b.themes>=3).map(b=><div key={b.key} onClick={()=>onOpen(issuesByKey[b.key])} className="flex items-center justify-between gap-3" style={{padding:"9px 0",borderBottom:"1px solid #F1F5F9",cursor:issuesByKey[b.key]?"pointer":"default"}}>
      <span className="flex items-center gap-2">{ragMap[b.key]&&<RagDot rag={ragMap[b.key].rag} size={9}/>}<span style={{fontWeight:600,fontSize:13}}>{b.summary} <span style={{color:C.muted,fontWeight:400,fontSize:11.5}}>· {b.bu}</span></span>{b.feedsExec&&<Chip label="feeds exec" color={C.navy} solid/>}</span>
      <span style={{flexShrink:0,fontSize:12,color:C.muted}}><b style={{color:C.navy}}>{b.themes}</b> themes · {b.bus} BUs · {b.count} links</span></div>);
  else if(which==="slippage") body=Object.entries(DATA.moves).filter(([k])=>issuesByKey[k]).sort((a,b)=>b[1]-a[1]).map(([k,n])=>{const it=issuesByKey[k];
      return <ItemRow key={k} it={it} right={<span><b style={{color:n>=3?RAG.Red:RAG.Amber}}>moved {n}x</b> · due {fmt(it.due)}</span>}/>;});
  else if(which==="unplanned"){const u=DATA.unplanned; body=[<div key="unplanned">
      <div className="flex flex-wrap gap-2" style={{margin:"2px 0 12px"}}>{Object.entries(u.byType).map(([t,n])=><Chip key={t} label={t+": "+n} color={C.navy}/>)}<Chip label={u.totalHours+"h logged"} color={"#0EA5E9"}/></div>
      <div style={{fontWeight:700,fontSize:12.5,margin:"4px 0 4px"}}>By delivering BU</div>
      {u.byBU.map(b=><div key={b.bu} className="flex items-center justify-between gap-3" style={{padding:"7px 0",borderBottom:"1px solid #F1F5F9"}}>
        <span style={{fontWeight:600,fontSize:13}}>{b.bu}</span>
        <span style={{flexShrink:0,fontSize:12,color:C.muted}}><b style={{color:C.navy}}>{b.count}</b> items · {b.hours}h</span></div>)}
      <div style={{fontWeight:700,fontSize:12.5,margin:"12px 0 4px"}}>Top parent epics</div>
      {u.byEpic.map(e=><div key={e.epic} onClick={()=>onOpen(issuesByKey[e.epic])} className="flex items-center justify-between gap-3" style={{padding:"7px 0",borderBottom:"1px solid #F1F5F9",cursor:issuesByKey[e.epic]?"pointer":"default"}}>
        <span className="flex items-center gap-2" style={{minWidth:0}}>{issuesByKey[e.epic]&&<RagDot rag={ragMap[e.epic].rag} size={9}/>}<span style={{fontWeight:600,fontSize:13}}>{e.summary} <span style={{color:C.muted,fontWeight:400,fontSize:11.5}}>· {e.bu}</span></span></span>
        <span style={{flexShrink:0,fontSize:12,color:C.muted}}><b style={{color:C.navy}}>{e.count}</b> unplanned</span></div>)}
    </div>];}
  return (
    <div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(15,23,42,0.35)",zIndex:55,display:"flex",alignItems:"flex-start",justifyContent:"center",padding:"6vh 16px"}}>
      <div onClick={e=>e.stopPropagation()} style={{width:560,maxWidth:"100%",maxHeight:"82vh",display:"flex",flexDirection:"column",background:"#fff",borderRadius:12,boxShadow:"0 20px 50px rgba(0,0,0,0.25)",overflow:"hidden"}}>
        <div className="flex justify-between items-start" style={{padding:"16px 18px 10px"}}>
          <div><div style={{fontSize:17,fontWeight:800,color:C.navy}}>{META.title}</div><div style={{fontSize:12,color:C.muted,marginTop:2,maxWidth:440}}>{META.blurb}</div></div>
          <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={20}/></button>
        </div>
        <div style={{padding:"0 18px",overflowY:"auto"}}>{body&&body.filter(Boolean).length?body:<div style={{padding:24,textAlign:"center",color:C.muted}}>Nothing to show.</div>}</div>
        <div className="flex justify-end" style={{padding:"12px 18px",borderTop:"1px solid "+C.border}}>
          <button onClick={()=>goTab(META.tab)} style={{background:C.navy,color:"#fff",border:"none",borderRadius:8,padding:"9px 16px",fontSize:13,fontWeight:700,cursor:"pointer"}}>{META.tabLabel} &#8594;</button>
        </div>
      </div>
    </div>
  );
}
